def normalize_fee_model_settings(raw_settings=None):
    """Early-safe KCS fee settings normalizer used during startup config loading."""
    def _local_clamp(value, min_value, max_value, default):
        try:
            numeric = float(value)
        except Exception:
            numeric = float(default)
        return max(float(min_value), min(float(max_value), numeric))

    settings = dict(DEFAULT_FEE_MODEL_SETTINGS)
    if isinstance(raw_settings, dict):
        for key in settings:
            if key in raw_settings:
                settings[key] = raw_settings.get(key)
    settings["use_kcs_fee_discount"] = bool(settings.get("use_kcs_fee_discount", False))
    settings["base_trade_fee_pct"] = _local_clamp(settings.get("base_trade_fee_pct", 0.10), 0.0, 2.0, 0.10)
    settings["kcs_fee_discount_pct"] = _local_clamp(settings.get("kcs_fee_discount_pct", 20.0), 0.0, 80.0, 20.0)
    settings["min_kcs_reserve_usdt"] = _local_clamp(settings.get("min_kcs_reserve_usdt", 10.0), 0.0, 1000.0, 10.0)
    settings["warn_low_kcs_reserve"] = bool(settings.get("warn_low_kcs_reserve", True))
    settings["auto_buy_kcs_enabled"] = bool(settings.get("auto_buy_kcs_enabled", False))
    settings["auto_buy_kcs_amount_usdt"] = _local_clamp(settings.get("auto_buy_kcs_amount_usdt", 5.0), 0.0, 100.0, 5.0)
    settings["auto_buy_kcs_min_usdt_balance"] = _local_clamp(settings.get("auto_buy_kcs_min_usdt_balance", 25.0), 0.0, 10000.0, 25.0)
    return settings


def normalize_execution_model_settings(raw_settings=None):
    """Early-safe execution realism settings used by backtest, scanner and live checks."""
    def _local_clamp(value, min_value, max_value, default):
        try:
            numeric = float(value)
        except Exception:
            numeric = float(default)
        return max(float(min_value), min(float(max_value), numeric))

    settings = dict(DEFAULT_EXECUTION_MODEL_SETTINGS)
    if isinstance(raw_settings, dict):
        for key in settings:
            if key in raw_settings:
                settings[key] = raw_settings.get(key)
    settings["execution_spread_pct"] = _local_clamp(settings.get("execution_spread_pct", 0.05), 0.0, 5.0, 0.05)
    settings["execution_slippage_pct"] = _local_clamp(settings.get("execution_slippage_pct", 0.05), 0.0, 5.0, 0.05)
    settings["execution_worst_slippage_pct"] = _local_clamp(settings.get("execution_worst_slippage_pct", 0.15), 0.0, 10.0, 0.15)
    settings["execution_max_allowed_slippage_pct"] = _local_clamp(settings.get("execution_max_allowed_slippage_pct", 0.50), 0.0, 10.0, 0.50)
    profile_key = str(settings.get("execution_realism_profile", "balanced_liquid") or "balanced_liquid").strip()
    if profile_key not in EXECUTION_REALISM_PROFILES:
        profile_key = "balanced_liquid"
    settings["execution_realism_profile"] = profile_key
    order_pref = str(settings.get("execution_order_type_preference", "market_taker") or "market_taker").strip().lower()
    if order_pref not in ("market_taker", "limit_maker"):
        order_pref = "market_taker"
    settings["execution_order_type_preference"] = order_pref
    return settings


def normalize_risk_governor_settings(raw_settings=None):
    """Early-safe risk governor settings for live-buy protection."""
    def _local_clamp(value, min_value, max_value, default):
        try:
            numeric = float(value)
        except Exception:
            numeric = float(default)
        return max(float(min_value), min(float(max_value), numeric))

    settings = dict(DEFAULT_RISK_GOVERNOR_SETTINGS)
    if isinstance(raw_settings, dict):
        for key in settings:
            if key in raw_settings:
                settings[key] = raw_settings.get(key)
    settings["risk_governor_enabled"] = bool(settings.get("risk_governor_enabled", True))
    settings["risk_max_daily_loss_usdt"] = _local_clamp(settings.get("risk_max_daily_loss_usdt", 25.0), 0.0, 100000.0, 25.0)
    settings["risk_max_weekly_loss_usdt"] = _local_clamp(settings.get("risk_max_weekly_loss_usdt", 75.0), 0.0, 100000.0, 75.0)
    settings["risk_emergency_volatility_halt_pct"] = _local_clamp(settings.get("risk_emergency_volatility_halt_pct", 8.0), 0.0, 100.0, 8.0)
    settings["risk_api_error_cooldown_minutes"] = int(_local_clamp(settings.get("risk_api_error_cooldown_minutes", 15), 0, 1440, 15))
    return settings


def normalize_minimum_edge_settings(raw_settings=None):
    """Early-safe minimum edge settings so costs cannot make tiny signals look profitable."""
    def _local_clamp(value, min_value, max_value, default):
        try:
            numeric = float(value)
        except Exception:
            numeric = float(default)
        return max(float(min_value), min(float(max_value), numeric))

    settings = dict(DEFAULT_MINIMUM_EDGE_SETTINGS)
    if isinstance(raw_settings, dict):
        for key in settings:
            if key in raw_settings:
                settings[key] = raw_settings.get(key)
    settings["minimum_edge_after_costs_enabled"] = bool(settings.get("minimum_edge_after_costs_enabled", True))
    settings["minimum_edge_buffer_pct"] = _local_clamp(settings.get("minimum_edge_buffer_pct", 0.15), 0.0, 10.0, 0.15)
    return settings


