def _log_suppressed_exception(context, exc, min_interval_seconds=60):
    """Loggar tidigare tysta fallback-fel utan att störa tradingflödet.

    Många fallback-block ska fortfarande kunna rädda UI/livebotten, men felet får
    inte försvinna helt. Rate-limit per feltyp gör att nätverksstrul inte fyller
    disken eller eventloggen.
    """
    try:
        context = str(context or "unknown")
        exc_type = type(exc).__name__
        exc_msg = str(exc).replace("\n", " ").strip()
        key = f"{context}|{exc_type}|{exc_msg[:180]}"
        now_ts = time.time()
        last_ts = float(_SUPPRESSED_EXCEPTION_LAST_LOG.get(key, 0.0))
        if now_ts - last_ts < float(min_interval_seconds):
            return
        if len(_SUPPRESSED_EXCEPTION_LAST_LOG) > 2000:
            _SUPPRESSED_EXCEPTION_LAST_LOG.clear()
        _SUPPRESSED_EXCEPTION_LAST_LOG[key] = now_ts
        line = (
            f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] "
            f"SUPPRESSED_EXCEPTION {context}: {exc_type}: {exc_msg}\n"
        )
        with SUPPRESSED_EXCEPTION_LOG_LOCK:
            with open(SUPPRESSED_EXCEPTION_FILE, "a", encoding="utf-8") as f_err:
                f_err.write(line)
    except BaseException:
        pass

