def normalize_ui_language(value):
    value = str(value or "en").strip().lower()
    if value in ("english", "eng", "en", "gb", "uk", "🇬🇧"):
        return "en"
    if value in ("svenska", "swedish", "swe", "sv", "se", "🇸🇪"):
        return "sv"
    return "en"


def read_ui_language_from_config():
    try:
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r", encoding="utf-8-sig") as f_lang:
                payload = json.load(f_lang)
            if isinstance(payload, dict):
                return normalize_ui_language(payload.get("ui_language", "en"))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L790', _suppressed_exc)
        pass
    return "en"


def get_ui_language():
    try:
        return normalize_ui_language(st.session_state.get("ui_language", read_ui_language_from_config()))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L798', _suppressed_exc)
        return read_ui_language_from_config()


def get_notification_language():
    """Language used by background threads and Telegram.

    The Streamlit session may not exist when live watcher threads send messages,
    so Telegram must primarily follow the language saved in bot_config.json.
    """
    try:
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r", encoding="utf-8-sig") as f_lang:
                payload = json.load(f_lang)
            if isinstance(payload, dict) and "ui_language" in payload:
                return normalize_ui_language(payload.get("ui_language", "en"))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L814', _suppressed_exc)
        pass
    try:
        return normalize_ui_language(st.session_state.get("ui_language", "en"))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L818', _suppressed_exc)
        return "en"


