def get_telegram_notification_settings(cfg=None):
    try:
        cfg = cfg if isinstance(cfg, dict) else load_bot_config()
    except Exception as _suppressed_exc:
        _log_suppressed_exception('get_telegram_notification_settings', _suppressed_exc)
        cfg = {}
    return {
        key: bool((cfg or {}).get(key, default_value))
        for key, default_value in TELEGRAM_NOTIFICATION_DEFAULTS.items()
    }


def is_telegram_category_enabled(category="general", cfg=None):
    settings = get_telegram_notification_settings(cfg)
    if not bool(settings.get("telegram_notifications_enabled", True)):
        return False
    key = TELEGRAM_CATEGORY_KEYS.get(str(category or "general").lower(), "telegram_notifications_enabled")
    return bool(settings.get(key, True))


def is_english_language(language_code=None):
    return normalize_ui_language(language_code if language_code is not None else get_notification_language()) == "en"


def translate_ui_text(value):
    if get_ui_language() != "en" or not isinstance(value, str):
        return value
    if not value:
        return value
    stripped = value.strip()
    if stripped.startswith("<style") or stripped.startswith("<script"):
        return value
    if value in EN_TRANSLATIONS:
        return EN_TRANSLATIONS[value]
    if stripped in EN_TRANSLATIONS:
        return value.replace(stripped, EN_TRANSLATIONS[stripped], 1)
    translated = value
    for sv_text, en_text in sorted(EN_REPLACEMENTS, key=lambda item: len(item[0]), reverse=True):
        translated = translated.replace(sv_text, en_text)
    return translated


def translate_visible_log_text(value):
    """Translate stored Swedish log text at render time without changing files on disk."""
    if not isinstance(value, str):
        return value
    try:
        cleaned = value.replace("b?ttre", "bättre")
        return translate_ui_text(cleaned)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('translate_visible_log_text', _suppressed_exc)
        return value


def translate_ui_option(value):
    if str(value) == "Contabo / delad VPS":
        return "Shared VPS" if get_ui_language() == "en" else "Delad VPS"
    if get_ui_language() != "en":
        return str(value)
    return translate_ui_text(str(value))


def has_streamlit_run_context():
    try:
        from streamlit.runtime.scriptrunner import get_script_run_ctx
        return get_script_run_ctx(suppress_warning=True) is not None
    except Exception as _suppressed_exc:
        _log_suppressed_exception('has_streamlit_run_context', _suppressed_exc)
        return True


def strip_widget_default_when_state_exists(method_name, kwargs):
    """Do not pass widget defaults when Streamlit already owns that key."""
    try:
        widget_key = kwargs.get("key")
        if not widget_key or not has_streamlit_run_context():
            return kwargs
        if widget_key not in st.session_state:
            return kwargs
        default_args_by_widget = {
            "checkbox": ("value",),
            "number_input": ("value",),
            "text_area": ("value",),
            "text_input": ("value",),
            "date_input": ("value",),
            "radio": ("index",),
            "selectbox": ("index",),
            "multiselect": ("default",),
        }
        for arg_name in default_args_by_widget.get(method_name, ()):
            kwargs.pop(arg_name, None)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('strip_widget_default_when_state_exists', _suppressed_exc)
    return kwargs


def _translate_first_arg(args, kwargs, method_name=None):
    args = list(args)
    if method_name in ("radio", "selectbox", "multiselect") and "format_func" not in kwargs:
        kwargs["format_func"] = translate_ui_option
    if method_name == "tabs" and args and isinstance(args[0], (list, tuple)):
        args[0] = [translate_ui_text(item) if isinstance(item, str) else item for item in args[0]]
    elif method_name == "metric":
        if args:
            args[0] = translate_ui_text(args[0])
        elif "label" in kwargs:
            kwargs["label"] = translate_ui_text(kwargs["label"])
    elif method_name in ("markdown", "write"):
        unsafe_html = bool(kwargs.get("unsafe_allow_html", False))
        if args and isinstance(args[0], str) and not unsafe_html:
            args[0] = translate_ui_text(args[0])
    else:
        if args and isinstance(args[0], str):
            args[0] = translate_ui_text(args[0])
    for key in ("label", "body", "help", "page_title"):
        if key in kwargs and isinstance(kwargs[key], str):
            kwargs[key] = translate_ui_text(kwargs[key])
    return tuple(args), kwargs


def patch_streamlit_i18n():
    if getattr(st, "_gurks_i18n_patched", False):
        return
    method_names = [
        "title", "header", "subheader", "markdown", "caption", "write",
        "info", "warning", "error", "success", "toast", "button",
        "checkbox", "radio", "selectbox", "multiselect", "number_input",
        "text_input", "text_area", "date_input", "metric", "expander",
        "tabs", "dialog", "set_page_config"
    ]

    def make_module_wrapper(method_name, original_func):
        def wrapped(*args, **kwargs):
            args, kwargs = _translate_first_arg(args, kwargs, method_name)
            kwargs = strip_widget_default_when_state_exists(method_name, kwargs)
            return original_func(*args, **kwargs)
        return wrapped

    for method_name in method_names:
        if hasattr(st, method_name):
            original_func = getattr(st, method_name)
            setattr(st, f"_gurks_orig_{method_name}", original_func)
            setattr(st, method_name, make_module_wrapper(method_name, original_func))

    try:
        from streamlit.delta_generator import DeltaGenerator

        def make_dg_wrapper(method_name, original_func):
            def wrapped(self, *args, **kwargs):
                args, kwargs = _translate_first_arg(args, kwargs, method_name)
                kwargs = strip_widget_default_when_state_exists(method_name, kwargs)
                return original_func(self, *args, **kwargs)
            return wrapped

        for method_name in method_names:
            if hasattr(DeltaGenerator, method_name):
                original_func = getattr(DeltaGenerator, method_name)
                setattr(DeltaGenerator, f"_gurks_orig_{method_name}", original_func)
                setattr(DeltaGenerator, method_name, make_dg_wrapper(method_name, original_func))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L911', _suppressed_exc)
        pass
    st._gurks_i18n_patched = True


def save_ui_language_to_config(language_code):
    language_code = normalize_ui_language(language_code)
    try:
        cfg = {}
        if os.path.exists(CONFIG_FILE):
            with open(CONFIG_FILE, "r", encoding="utf-8-sig") as f_lang:
                loaded = json.load(f_lang)
            if isinstance(loaded, dict):
                cfg = loaded
        cfg["ui_language"] = language_code
        atomic_write_json_file(CONFIG_FILE, cfg, indent=4)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L930', _suppressed_exc)
        pass
    try:
        st.session_state.ui_language = language_code
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L934', _suppressed_exc)
        pass
    return language_code


def refresh_translated_widget_render_state(except_key=None):
    """Language changes must be visual only; never delete user-selected widget state."""
    return


def save_ui_language_selection(widget_key):
    selected_flag = st.session_state.get(widget_key, UI_LANGUAGE_OPTIONS.get(get_ui_language(), "🇸🇪"))
    old_language = get_ui_language()
    new_language = UI_LANGUAGE_FROM_FLAG.get(selected_flag, "sv")
    save_ui_language_to_config(new_language)
    if normalize_ui_language(new_language) != normalize_ui_language(old_language):
        refresh_translated_widget_render_state(except_key=widget_key)


def render_language_switcher(widget_key="ui_language_selector", collapsed=True):
    current_lang = get_ui_language()
    options = [UI_LANGUAGE_OPTIONS["sv"], UI_LANGUAGE_OPTIONS["en"]]
    if widget_key not in st.session_state:
        st.session_state[widget_key] = UI_LANGUAGE_OPTIONS.get(current_lang, "SE")
    elif st.session_state.get(widget_key) not in options:
        st.session_state[widget_key] = UI_LANGUAGE_OPTIONS.get(normalize_ui_language(st.session_state.get(widget_key)), UI_LANGUAGE_OPTIONS.get(current_lang, "SE"))
    selected_flag = st.radio(
        "Språk",
        options,
        index=options.index(UI_LANGUAGE_OPTIONS.get(current_lang, "SE")),
        horizontal=True,
        key=widget_key,
        on_change=save_ui_language_selection,
        args=(widget_key,),
        label_visibility="collapsed" if collapsed else "visible",
        help="Växla UI-språk. Valet sparas i bot_config.json."
    )
    selected_lang = UI_LANGUAGE_FROM_FLAG.get(selected_flag, current_lang)
    if selected_lang != current_lang:
        save_ui_language_to_config(selected_lang)
        st.rerun()
    return selected_lang

