def get_scan_modes_for_cycle(mode=None):
    scan_mode = normalize_scan_trading_mode(mode or "swing")
    if scan_mode == SCAN_MODE_BOTH:
        return ["swing", "day"]
    return [normalize_trading_mode(scan_mode)]


