def get_active_trading_mode_summary(language=None):
    english = is_english_language(language)
    mode_order = ["swing", "day"]
    active_modes = []
    try:
        active_modes = normalize_active_trading_modes(st.session_state.get("active_trading_modes", []), allow_empty=True)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1271', _suppressed_exc)
        active_modes = []
    if not active_modes:
        try:
            cfg = load_bot_config()
            active_modes = normalize_active_trading_modes(cfg.get("active_trading_modes", []), allow_empty=True)
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1277', _suppressed_exc)
            active_modes = []
    try:
        for _, position in load_open_positions().items():
            pos_mode = normalize_trading_mode(position.get("trading_mode", "swing"))
            if pos_mode not in active_modes:
                active_modes.append(pos_mode)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1284', _suppressed_exc)
        pass
    if not active_modes:
        active_modes = [get_active_trading_mode()]
    active_modes = [mode for mode in mode_order if mode in active_modes]
    if len(active_modes) == 2:
        return "Swing Trading + Day Trading"
    if active_modes:
        return get_trading_mode_label(active_modes[0])
    return "No active mode" if english else "Inget aktivt läge"


