def _b64encode_bytes(raw_bytes):
    return base64.b64encode(raw_bytes).decode("ascii")


def _b64decode_bytes(text_value):
    return base64.b64decode(str(text_value).encode("ascii"))


def _password_candidates(password):
    raw_password = str(password or "")
    candidates = []
    for value in (raw_password, raw_password.strip()):
        for form in ("NFC", "NFKC", "NFD", "NFKD"):
            normalized = unicodedata.normalize(form, value)
            if normalized not in candidates:
                candidates.append(normalized)
    return candidates


def hash_login_password(password, salt=None, iterations=310000):
    salt_bytes = salt if isinstance(salt, bytes) else secrets.token_bytes(32)
    normalized_password = unicodedata.normalize("NFC", str(password or ""))
    derived_key = hashlib.pbkdf2_hmac("sha256", normalized_password.encode("utf-8"), salt_bytes, int(iterations))
    return {
        "algorithm": "pbkdf2_sha256",
        "iterations": int(iterations),
        "salt": _b64encode_bytes(salt_bytes),
        "password_hash": _b64encode_bytes(derived_key)
    }


def load_auth_config():
    try:
        if not os.path.exists(AUTH_FILE):
            return {}
        with open(AUTH_FILE, "r", encoding="utf-8-sig") as f_auth:
            payload = json.load(f_auth)
        return payload if isinstance(payload, dict) else {}
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1348', _suppressed_exc)
        return {}


def verify_login_password(password, auth_config):
    try:
        if not auth_config:
            return False

        password_entries = auth_config.get("passwords")
        if not isinstance(password_entries, list):
            password_entries = [auth_config]

        for entry in password_entries:
            try:
                if not isinstance(entry, dict) or entry.get("algorithm") != "pbkdf2_sha256":
                    continue
                iterations = int(entry.get("iterations", 310000))
                salt_bytes = _b64decode_bytes(entry.get("salt", ""))
                expected_hash = _b64decode_bytes(entry.get("password_hash", ""))
                for candidate_password in _password_candidates(password):
                    candidate_hash = hashlib.pbkdf2_hmac("sha256", candidate_password.encode("utf-8"), salt_bytes, iterations)
                    if hmac.compare_digest(candidate_hash, expected_hash):
                        return True
            except Exception as _suppressed_exc:
                _log_suppressed_exception('bare_except_L1372', _suppressed_exc)
                continue
        return False
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1375', _suppressed_exc)
        return False


