def atomic_write_json_file(path, payload, indent=2):
    tmp_path = None
    try:
        parent_dir = os.path.dirname(os.path.abspath(path)) or "."
        os.makedirs(parent_dir, exist_ok=True)
        tmp_path = os.path.join(
            parent_dir,
            f".{os.path.basename(path)}.{os.getpid()}.{threading.get_ident()}.{secrets.token_hex(4)}.tmp"
        )
        with open(tmp_path, "w", encoding="utf-8") as f_json:
            json.dump(payload, f_json, ensure_ascii=False, indent=indent)
            f_json.flush()
            try:
                os.fsync(f_json.fileno())
            except Exception as _suppressed_exc:
                _log_suppressed_exception('atomic_write_json_fsync', _suppressed_exc)
                pass
        os.replace(tmp_path, path)
        try:
            cached_json_file.clear()
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1419', _suppressed_exc)
            pass
        return True
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1422', _suppressed_exc)
        try:
            if tmp_path and os.path.exists(tmp_path):
                os.remove(tmp_path)
        except Exception as cleanup_exc:
            _log_suppressed_exception('atomic_write_json_cleanup', cleanup_exc)
        return False


