def migrate_existing_config_file():
    """Fyller i nya config-nycklar vid uppstart utan att skriva över användarens värden."""
    try:
        if not os.path.exists(CONFIG_FILE):
            return False
        with open(CONFIG_FILE, "r", encoding="utf-8-sig") as f_cfg:
            raw_cfg = json.load(f_cfg)
        if not isinstance(raw_cfg, dict):
            return False
        normalized_defaults = load_bot_config()
        changed = False

        def fill_missing(target, defaults):
            nonlocal changed
            if not isinstance(target, dict) or not isinstance(defaults, dict):
                return
            for key, value in defaults.items():
                if key not in target:
                    target[key] = value
                    changed = True
                elif isinstance(target.get(key), dict) and isinstance(value, dict):
                    fill_missing(target[key], value)

        fill_missing(raw_cfg, normalized_defaults)
        normalized_language = normalize_ui_language(raw_cfg.get("ui_language", "en"))
        if raw_cfg.get("ui_language") != normalized_language:
            raw_cfg["ui_language"] = normalized_language
            changed = True
        if changed:
            return atomic_write_json_file(CONFIG_FILE, raw_cfg, indent=4)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1475', _suppressed_exc)
        return False
    return False


