def enforce_login_wall():
    if os.getenv("BOT_DISABLE_LOGIN", "0") == "1":
        return
    if not is_login_wall_enabled_from_config():
        st.session_state.auth_ok = True
        return

    if st.session_state.get("auth_ok", False):
        with st.sidebar:
            if st.button(translate_ui_text("🔒 Logga ut"), use_container_width=True, key="logout_btn"):
                st.session_state.auth_ok = False
                st.rerun()
        return

    inject_login_theme_css()
    auth_config = load_auth_config()
    st.title("🔐 Gurks Trading Bot")
    if not auth_config_has_user_password(auth_config):
        st.error(translate_ui_text("Loginväggen är aktiv men inget eget lösenord är sparat. Starta tillfälligt med BOT_DISABLE_LOGIN=1 och sätt ett nytt lösenord i Inställningar & Strategi."))
        st.stop()

    with st.container(border=True):
        render_language_switcher("login_ui_language_selector", collapsed=False)
        st.subheader(translate_ui_text("Logga in"))
        st.caption(translate_ui_text("Lösenordet verifieras mot PBKDF2-hash i secure_auth.json. Inget klartextlösenord lagras i bot.py."))
        password = st.text_input(translate_ui_text("Lösenord"), type="password", key="login_password_input")
        login_clicked = st.button(translate_ui_text("Logga in"), type="primary", use_container_width=True, key="login_submit_btn")
        if login_clicked:
            if verify_login_password(password, auth_config):
                st.session_state.auth_ok = True
                st.rerun()
            else:
                st.error(translate_ui_text("Fel lösenord."))
    st.stop()


def _status_text_is_running(text):
    text = str(text or "")
    terminal_markers = [
        "Viloläge", "Slutförd", "stoppades", "avbröts", "Kritiskt",
        "Skanning klar", "CSV skapades", "Kunde inte", "matchar inte",
        "Stoppsignal skickad", "Nödstopp"
    ]
    return bool(text.strip()) and not any(marker in text for marker in terminal_markers)


def _status_text_is_stop_request(text):
    text = str(text or "")
    return "Stoppsignal skickad" in text or "Nödstopp" in text


def write_opt_progress_status(text, running=None, cycle_complete=False):
    try:
        text = str(text or "").strip()
        if running is None:
            running = _status_text_is_running(text)
        should_clear_cooldown = any(
            marker in text
            for marker in ("Viloläge", "Avaktiverad", "Stoppsignal", "Nödstopp", "stoppades", "avbröts")
        )
        payload = {
            "text": text,
            "running": bool(running),
            "updated_at": datetime.now().isoformat(timespec="seconds")
        }
        if cycle_complete:
            completed_at = datetime.now()
            payload["completed_at"] = completed_at.isoformat(timespec="seconds")
            payload["next_run_after"] = (completed_at + timedelta(seconds=get_opt_auto_restart_delay_seconds())).isoformat(timespec="seconds")
        elif not running and not should_clear_cooldown:
            old_payload = load_opt_progress_payload()
            old_next_run = old_payload.get("next_run_after")
            old_completed_at = old_payload.get("completed_at")
            if old_completed_at:
                try:
                    old_next_run = (datetime.fromisoformat(old_completed_at) + timedelta(seconds=get_opt_auto_restart_delay_seconds())).isoformat(timespec="seconds")
                except Exception as _suppressed_exc:
                    _log_suppressed_exception('bare_except_L1695', _suppressed_exc)
            if not old_next_run and old_payload.get("updated_at") and not _status_text_is_running(old_payload.get("text", "")):
                try:
                    migrated_completed_at = datetime.fromisoformat(old_payload["updated_at"])
                    migrated_next_run = migrated_completed_at + timedelta(seconds=get_opt_auto_restart_delay_seconds())
                    if migrated_next_run > datetime.now():
                        old_completed_at = migrated_completed_at.isoformat(timespec="seconds")
                        old_next_run = migrated_next_run.isoformat(timespec="seconds")
                except Exception as _suppressed_exc:
                    _log_suppressed_exception('bare_except_L1697', _suppressed_exc)
                    pass
            if old_next_run:
                try:
                    if datetime.fromisoformat(old_next_run) > datetime.now():
                        payload["completed_at"] = old_completed_at
                        payload["next_run_after"] = old_next_run
                except Exception as _suppressed_exc:
                    _log_suppressed_exception('bare_except_L1704', _suppressed_exc)
                    pass
        tmp_progress_file = (
            f"{OPT_PROGRESS_FILE}.{os.getpid()}.{threading.get_ident()}."
            f"{secrets.token_hex(4)}.tmp"
        )
        last_write_error = None
        for attempt in range(6):
            try:
                with open(tmp_progress_file, "w", encoding="utf-8") as f_prog:
                    json.dump(payload, f_prog, ensure_ascii=False, indent=2)
                os.replace(tmp_progress_file, OPT_PROGRESS_FILE)
                last_write_error = None
                break
            except PermissionError as progress_write_err:
                last_write_error = progress_write_err
                time.sleep(0.05 * (attempt + 1))
            except OSError as progress_write_err:
                last_write_error = progress_write_err
                time.sleep(0.05 * (attempt + 1))
        if last_write_error is not None:
            raise last_write_error
        try:
            if os.path.exists(tmp_progress_file):
                os.remove(tmp_progress_file)
        except Exception as cleanup_err:
            _log_suppressed_exception("opt_progress_tmp_cleanup", cleanup_err)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1710', _suppressed_exc)
        pass


def set_optimization_disabled_status(text="Viloläge. Avaktiverad."):
    try:
        st.session_state.optimization_active = False
        st.session_state.opt_thread_running = False
        st.session_state.opt_progress_text = text
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1719', _suppressed_exc)
        pass
    write_opt_progress_status(text, running=False)


def load_opt_progress_payload():
    try:
        if not os.path.exists(OPT_PROGRESS_FILE):
            return {}
        with open(OPT_PROGRESS_FILE, "r", encoding="utf-8") as f_prog:
            raw = f_prog.read().strip()
        if not raw:
            return {}
        try:
            payload = json.loads(raw)
            if isinstance(payload, dict):
                return payload
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1736', _suppressed_exc)
            pass

        legacy_lines = [line.strip() for line in raw.splitlines() if line.strip()]
        if legacy_lines and all(line == "1" for line in legacy_lines):
            return {
                "text": f"⏳ Skanning aktiv: {len(legacy_lines):,} matriser har rapporterat framsteg.",
                "running": True,
                "updated_at": None
            }
        return {"text": raw, "running": _status_text_is_running(raw), "updated_at": None}
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1747', _suppressed_exc)
        return {}


def read_opt_progress_status():
    payload = load_opt_progress_payload()
    return str(payload.get("text", "")).strip()


def opt_progress_is_recently_running(max_age_seconds=120):
    payload = load_opt_progress_payload()
    if _status_text_is_stop_request(payload.get("text", "")):
        return False
    if not payload.get("running"):
        return False
    updated_at = payload.get("updated_at")
    if not updated_at:
        return False
    try:
        age = (datetime.now() - datetime.fromisoformat(updated_at)).total_seconds()
        return age <= max_age_seconds
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1768', _suppressed_exc)
        return False


def format_seconds_short(seconds_value):
    try:
        total_seconds = max(0, int(seconds_value))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1775', _suppressed_exc)
        total_seconds = 0
    minutes, seconds = divmod(total_seconds, 60)
    hours, minutes = divmod(minutes, 60)
    if hours > 0:
        return f"{hours}h {minutes}m"
    if minutes > 0:
        return f"{minutes}m {seconds}s"
    return f"{seconds}s"


def opt_auto_restart_remaining_seconds():
    payload = load_opt_progress_payload()
    if _status_text_is_stop_request(payload.get("text", "")):
        return 0
    if payload.get("running"):
        return 0

    target_iso = payload.get("next_run_after")
    completed_at = payload.get("completed_at")
    if completed_at:
        try:
            target_iso = (datetime.fromisoformat(completed_at) + timedelta(seconds=get_opt_auto_restart_delay_seconds())).isoformat(timespec="seconds")
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1793', _suppressed_exc)
            target_iso = payload.get("next_run_after")
    if not target_iso and payload.get("updated_at") and not _status_text_is_running(payload.get("text", "")):
        try:
            target_iso = (datetime.fromisoformat(payload["updated_at"]) + timedelta(seconds=get_opt_auto_restart_delay_seconds())).isoformat(timespec="seconds")
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1797', _suppressed_exc)
            target_iso = None

    if not target_iso:
        return 0

    try:
        return max(0, int((datetime.fromisoformat(target_iso) - datetime.now()).total_seconds()))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1805', _suppressed_exc)
        return 0


def get_opt_auto_restart_delay_seconds(default_seconds=None):
    default_seconds = int(default_seconds or OPT_AUTO_RESTART_DELAY_SECONDS)
    minutes = None
    if has_streamlit_run_context():
        try:
            minutes = st.session_state.get("opt_restart_interval_minutes", None)
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1813', _suppressed_exc)
            minutes = None
    if minutes is None:
        try:
            cfg_path = globals().get("CONFIG_FILE")
            if cfg_path and os.path.exists(cfg_path):
                with open(cfg_path, "r", encoding="utf-8-sig") as f_cfg:
                    minutes = json.load(f_cfg).get("opt_restart_interval_minutes", default_seconds / 60)
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L1821', _suppressed_exc)
            minutes = default_seconds / 60
    try:
        return int(_clamp(float(minutes), 1, 1440, default_seconds / 60) * 60)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L1825', _suppressed_exc)
        return default_seconds


def refresh_execution_realism_calibration_after_scan(reason="scan_finished"):
    """Refresh KuCoin live-calibrated execution settings after a scan lifecycle ends.

    This intentionally runs only when the user has selected the KuCoin live-calibrated
    profile. Static execution profiles must stay stable across scans.
    """
    try:
        cfg = load_bot_config()
        if str(cfg.get("execution_realism_profile", "balanced_liquid")) != "kucoin_live_calibrated":
            return False, "skipped_static_profile"
        calibrator = globals().get("calibrate_execution_realism_from_kucoin")
        if not callable(calibrator):
            return False, "calibrator_not_ready"

        calibrated_payload = calibrator(cfg, max_symbols=6)
        calibrated_at = str(calibrated_payload.get("execution_calibrated_at", datetime.now().isoformat(timespec="seconds")))
        calibration_msg = (
            f"KuCoin live calibration refreshed after scan: "
            f"{calibrated_payload.get('execution_calibration_symbols', '')} | "
            f"p80 {calibrated_payload.get('execution_calibration_p80_spread_pct', 0.0):.4f}% | "
            f"{calibrated_at}"
        )
        fresh_cfg = load_bot_config()
        fresh_cfg.update(calibrated_payload)
        fresh_cfg["execution_last_calibration_msg"] = calibration_msg
        fresh_cfg["execution_auto_calibrated_after_scan_at"] = calibrated_at
        fresh_cfg["execution_auto_calibration_reason"] = str(reason or "scan_finished")
        fresh_cfg.pop("execution_auto_calibration_last_error", None)
        atomic_write_json_file(CONFIG_FILE, fresh_cfg, indent=4)
        try:
            append_system_event(
                f"🎯 Executionvärden uppdaterade från KuCoin-orderbok efter skanning: "
                f"{calibrated_payload.get('execution_calibration_symbols', '')}"
            )
        except Exception as log_err:
            _log_suppressed_exception("execution_auto_calibration_event_log", log_err)
        return True, calibration_msg
    except Exception as calibration_err:
        _log_suppressed_exception("execution_auto_calibration_after_scan", calibration_err, min_interval_seconds=300)
        try:
            fresh_cfg = load_bot_config()
            fresh_cfg["execution_auto_calibration_last_error"] = str(calibration_err)
            fresh_cfg["execution_auto_calibration_failed_at"] = datetime.now().isoformat(timespec="seconds")
            atomic_write_json_file(CONFIG_FILE, fresh_cfg, indent=4)
        except Exception as cfg_err:
            _log_suppressed_exception("execution_auto_calibration_error_persist", cfg_err)
        return False, str(calibration_err)


