        cfg["scan_multi_coin_ranking_mode"] = normalize_multi_coin_ranking_mode(st.session_state.get("scan_multi_coin_ranking_mode_input", st.session_state.get("scan_multi_coin_ranking_mode", cfg.get("scan_multi_coin_ranking_mode", "hybrid"))))
