        cfg.update(collect_scan_param_config_from_state(cfg))
            
        # Skriv tillbaka de uppdaterade värdena säkert till bot_config.json
        atomic_write_json_file(CONFIG_FILE, cfg, indent=4)
            
        # Synkronisera session_state live
        st.session_state.optimization_active = cfg["optimization_active_saved"]
        st.session_state.alert_mode = cfg["telegram_alert_mode"]
        st.session_state.alert_threshold = cfg["telegram_alert_threshold"]
