        st.session_state.telegram_alert_thresholds = cfg["telegram_alert_thresholds"]
        st.session_state.telegram_alert_logic = cfg["telegram_alert_logic"]
        for tg_key in TELEGRAM_NOTIFICATION_DEFAULTS:
            st.session_state[tg_key] = cfg[tg_key]
        st.session_state.opt_scan_days = opt_scan_days
        st.session_state.optimization_engine = cfg["optimization_engine"]
