        st.session_state.scan_profile_name = cfg["scan_profile_name"]
        st.session_state.scan_param_range_profile = cfg["scan_param_range_profile"]
        st.session_state.scan_randomize_each_cycle = cfg["scan_randomize_each_cycle"]
        st.session_state.scan_randomize_coins_each_cycle = cfg["scan_randomize_coins_each_cycle"]
