def get_trading_mode_profile(mode=None):
    return dict(TRADING_MODE_PROFILES.get(normalize_trading_mode(mode), TRADING_MODE_PROFILES["swing"]))


def apply_trading_mode_profile_to_config(cfg, mode=None, preserve_running=True):
    cfg = dict(cfg or {})
    mode = normalize_trading_mode(mode or cfg.get("trading_mode", "swing"))
    profile = get_trading_mode_profile(mode)
    running_value = cfg.get("running", False)
    optimization_value = cfg.get("optimization_active_saved", False)
    preserved_balance = cfg.get("opt_balance", 295.74)
    preserved_allocations = cfg.get("allocations")
    preserved_alerts = {
        "telegram_alert_mode": cfg.get("telegram_alert_mode", "USDT"),
        "telegram_alert_threshold": cfg.get("telegram_alert_threshold", 5.0),
        "telegram_alert_metrics": cfg.get("telegram_alert_metrics", ["Procent (%)"]),
        "telegram_alert_thresholds": cfg.get("telegram_alert_thresholds", dict(DEFAULT_ALERT_THRESHOLDS)),
        "telegram_alert_logic": cfg.get("telegram_alert_logic", "ANY"),
    }
    for key, value in profile.items():
        if key in ("profile_name", "description"):
            continue
        cfg[key] = value
    cfg["trading_mode"] = mode
    cfg["trading_mode_profile"] = profile.get("profile_name")
    cfg["opt_balance"] = preserved_balance
    if isinstance(preserved_allocations, dict) and preserved_allocations:
        cfg["allocations"] = preserved_allocations
    cfg.update(preserved_alerts)
    if preserve_running:
        cfg["running"] = running_value
        cfg["optimization_active_saved"] = optimization_value
    return cfg


def apply_trading_mode_profile_to_session(mode=None):
    mode = normalize_trading_mode(mode or st.session_state.get("trading_mode", "swing"))
    profile = get_trading_mode_profile(mode)
    st.session_state.trading_mode = mode
    st.session_state.trading_mode_profile = profile.get("profile_name")
    for key, value in profile.items():
        if key in ("profile_name", "description"):
            continue
        st.session_state[key] = value
    st.session_state.opt_tf_input = list(profile.get("opt_tf_list", [profile.get("selected_timeframe", "1h")]))
    st.session_state.pending_opt_scan_days_input = int(profile.get("opt_scan_days", 60))
    apply_scan_param_config_to_session(profile)
    return profile


def save_trading_mode_profile(mode):
    mode = normalize_trading_mode(mode)
    cfg = apply_trading_mode_profile_to_config(load_bot_config(), mode, preserve_running=True)
    atomic_write_json_file(CONFIG_FILE, cfg, indent=4)
    apply_trading_mode_profile_to_session(mode)
    try:
        append_system_event(f"TRADING MODE: Växlade till {get_trading_mode_label(mode)}. Standardprofilen laddades automatiskt.")
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L5864', _suppressed_exc)
        pass
    return cfg


