def maybe_randomize_scan_cycle_config(cfg=None, persist=True):
    cfg = dict(cfg or load_bot_config())
    if not bool(cfg.get("scan_randomize_each_cycle", False)):
        return cfg, ""
    rng = random.Random(int(time.time() * 1000) ^ os.getpid())
    locked_matrix_depth = cfg.get("opt_matrix_depth")
    locked_scan_days = cfg.get("opt_scan_days")
    locked_worker_count = cfg.get("opt_worker_count", 0)
    scan_mode_for_random = normalize_scan_trading_mode(cfg.get("opt_trading_mode", cfg.get("trading_mode", "swing")))
    # Random mode must not silently swap the user's selected preset profile. It only
    # varies fields inside the currently selected Swing/Day profile envelope.
    selected_profile = cfg.get("scan_profile_name")
    if selected_profile not in SCAN_PROFILE_PRESETS:
        selected_profile = "Day Trading Profile" if scan_mode_for_random == "day" else "Swing Profile"
        cfg["scan_profile_name"] = selected_profile
    if locked_matrix_depth:
        cfg["opt_matrix_depth"] = locked_matrix_depth
    cfg["opt_worker_count"] = locked_worker_count

    selected_range = cfg.get("scan_param_range_profile")
    if selected_range not in SCAN_PARAM_RANGE_PRESETS:
        selected_range = "Day Trading Intradag" if scan_mode_for_random == "day" else "Balanserad standard"
        cfg["scan_param_range_profile"] = selected_range
    cfg = randomize_full_scan_fields(cfg, selected_profile, rng)
    cfg = randomize_scan_parameter_ranges(cfg, scan_mode_for_random, rng)
    if locked_scan_days is not None:
        cfg["opt_scan_days"] = locked_scan_days
    cfg["opt_worker_count"] = locked_worker_count

    cfg["last_randomized_scan_profile"] = selected_profile
    cfg["last_randomized_range_profile"] = selected_range
    cfg["last_randomized_scan_at"] = datetime.now().isoformat(timespec="seconds")
    if persist:
        cfg = save_scan_config_fragment(cfg)
    coin_status = (
        f"Coins {'slumpade' if bool(cfg.get('scan_randomize_coins_each_cycle', True)) else 'låsta'}: {cfg.get('opt_coins_raw')} | "
        f"Fördelning {'slumpad' if bool(cfg.get('scan_randomize_allocation_each_cycle', cfg.get('scan_randomize_coins_each_cycle', True))) else 'låst'}: {cfg.get('opt_pcts_raw')}%"
    )
    return cfg, (
        f"🎲 Slumpade nästa skanning: {selected_profile} + {selected_range} | "
        f"TF {','.join(cfg.get('opt_tf_list', []))} | dagar låst: {cfg.get('opt_scan_days')} | "
        f"Min trades {cfg.get('opt_min_trades', 0)} | Djup låst: {cfg.get('opt_matrix_depth')} | "
        f"Workers låst: {cfg.get('opt_worker_count', 0)} | {coin_status}"
    )


def get_optimization_leaderboard_limit(limit=None):
    if limit is not None:
        try:
            return max(3, int(limit))
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L6405', _suppressed_exc)
            return OPT_LEADERBOARD_DEFAULT_MAX_ROWS
    try:
        return max(3, int(os.getenv("BOT_OPT_MAX_RESULTS", str(OPT_LEADERBOARD_DEFAULT_MAX_ROWS))))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6409', _suppressed_exc)
        return OPT_LEADERBOARD_DEFAULT_MAX_ROWS


def normalize_optimization_frame(df, columns=None):
    if df is None or getattr(df, "empty", True):
        return pd.DataFrame(columns=columns or [])
    clean_df = df.copy()
    if 'Profit_USDT' not in clean_df.columns:
        clean_df['Profit_USDT'] = 0.0
    clean_df['Profit_USDT'] = pd.to_numeric(clean_df['Profit_USDT'], errors='coerce').fillna(0.0)
    if 'Fitness_Score' not in clean_df.columns:
        clean_df['Fitness_Score'] = clean_df['Profit_USDT']
    clean_df['Fitness_Score'] = pd.to_numeric(clean_df['Fitness_Score'], errors='coerce').fillna(clean_df['Profit_USDT']).astype(float)
    extreme_ratio_mask = pd.Series(False, index=clean_df.index)
    for metric_col in ('Sharpe_Ratio', 'Sortino_Ratio', 'Max_Drawdown_Pct', 'InSample_Profit_USDT', 'OutSample_Profit_USDT'):
        if metric_col in clean_df.columns:
            clean_df[metric_col] = pd.to_numeric(clean_df[metric_col], errors='coerce').fillna(0.0)
    for ratio_col in ('Sharpe_Ratio', 'Sortino_Ratio'):
        if ratio_col in clean_df.columns:
            extreme_ratio_mask = extreme_ratio_mask | (clean_df[ratio_col].abs() > 25.0)
            clean_df[ratio_col] = clean_df[ratio_col].clip(-25.0, 25.0)
    try:
        winrate_series = clean_df['WinRate_Pct'] if 'WinRate_Pct' in clean_df.columns else pd.Series(0.0, index=clean_df.index)
        winrate_numeric = winrate_series.astype(str).str.replace('%', '', regex=False).str.replace(',', '.', regex=False)
        winrate_numeric = pd.to_numeric(winrate_numeric, errors='coerce').fillna(0.0)
        has_risk_columns = all(col in clean_df.columns for col in ('Sharpe_Ratio', 'Sortino_Ratio', 'Max_Drawdown_Pct'))
        needs_fitness_recalc = (
            extreme_ratio_mask
            | (clean_df['Fitness_Score'].abs() > 10000.0)
            | (clean_df.get('Max_Drawdown_Pct', pd.Series(0.0, index=clean_df.index)) > 20.0)
        )
        if has_risk_columns:
            needs_fitness_recalc = pd.Series(True, index=clean_df.index)
        if needs_fitness_recalc.any():
            sharpe = clean_df.get('Sharpe_Ratio', pd.Series(0.0, index=clean_df.index))
            sortino = clean_df.get('Sortino_Ratio', pd.Series(0.0, index=clean_df.index))
            selected_ratio = (sharpe + sortino) / 2.0
            out_sample = clean_df.get('OutSample_Profit_USDT', clean_df['Profit_USDT'])
            max_dd = clean_df.get('Max_Drawdown_Pct', pd.Series(0.0, index=clean_df.index))
            recalculated = (
                (selected_ratio * 115.0)
                + (out_sample * 1.65)
                + (clean_df['Profit_USDT'] * 0.28)
                + (winrate_numeric * 0.18)
                - (max_dd * 3.0)
                - (max_dd.sub(10.0).clip(lower=0.0) * 10.0)
                - (max_dd.sub(20.0).clip(lower=0.0).pow(2) * 1.75)
                - (out_sample.le(0.0).astype(float) * 150.0)
            )
            clean_df.loc[needs_fitness_recalc, 'Fitness_Score'] = recalculated.loc[needs_fitness_recalc].round(4)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6460', _suppressed_exc)
        pass
    if columns:
        for col in columns:
            if col not in clean_df.columns:
                clean_df[col] = "swing" if col == "Trading_Mode" else ""
        clean_df = clean_df.reindex(columns=columns)
    elif "Trading_Mode" not in clean_df.columns:
        clean_df["Trading_Mode"] = "swing"
    try:
        clean_df["Trading_Mode"] = clean_df["Trading_Mode"].apply(normalize_trading_mode)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6471', _suppressed_exc)
        pass
    return clean_df


