def get_opt_min_trades(default=0):
    if has_streamlit_run_context():
        try:
            state_value = st.session_state.get("opt_min_trades_input", st.session_state.get("opt_min_trades", None))
            if state_value is not None:
                return int(_clamp(state_value, 0, 100000, default))
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L6490', _suppressed_exc)
            pass
    try:
        cfg = load_bot_config()
        return int(_clamp(cfg.get("opt_min_trades", default), 0, 100000, default))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6495', _suppressed_exc)
        return int(default)


def filter_optimization_min_trades(df, min_trades=None):
    if df is None or getattr(df, "empty", True):
        return df
    try:
        min_trades = get_opt_min_trades(0) if min_trades is None else int(float(min_trades))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6504', _suppressed_exc)
        min_trades = 0
    if min_trades <= 0 or 'Total_Trades' not in df.columns:
        return df
    try:
        trades = pd.to_numeric(
            df['Total_Trades'].astype(str).str.replace('%', '', regex=False).str.replace(',', '.', regex=False),
            errors='coerce'
        ).fillna(0)
        return df.loc[trades >= min_trades].reset_index(drop=True)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6514', _suppressed_exc)
        return df


def read_top_optimization_frame(export_filename=None, max_rows=None, columns=None):
    export_filename = export_filename or OPT_EXPORT_FILE
    max_rows = get_optimization_leaderboard_limit(max_rows)
    if not os.path.exists(export_filename) or os.path.getsize(export_filename) <= 0:
        return pd.DataFrame(columns=columns or [])

    mtime_ns, size_bytes = file_cache_signature(export_filename)
    min_trades = get_opt_min_trades(0)
    columns_tuple = tuple(columns) if columns else tuple()
    return cached_top_optimization_frame(
        export_filename,
        mtime_ns,
        size_bytes,
        int(max_rows),
        int(min_trades),
        columns_tuple
    ).copy()


def compact_optimization_leaderboard(export_filename=None, columns=None, max_rows=None):
    export_filename = export_filename or OPT_EXPORT_FILE
    max_rows = get_optimization_leaderboard_limit(max_rows)
    with CSV_WRITE_LOCK:
        top_df = read_top_optimization_frame(export_filename, max_rows, columns)
        if top_df.empty:
            if not os.path.exists(export_filename) or os.path.getsize(export_filename) <= 0:
                pd.DataFrame(columns=columns or []).to_csv(export_filename, index=False)
            return 0
        tmp_filename = f"{export_filename}.tmp"
        top_df.to_csv(tmp_filename, index=False)
        os.replace(tmp_filename, export_filename)
        try:
            cached_top_optimization_frame.clear()
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L6551', _suppressed_exc)
            pass
        return len(top_df)


def read_optimization_frame_for_write(export_filename=None, columns=None):
    export_filename = export_filename or OPT_EXPORT_FILE
    if not os.path.exists(export_filename) or os.path.getsize(export_filename) <= 0:
        return pd.DataFrame(columns=columns or [])
    try:
        existing_df = pd.read_csv(export_filename)
    except pd.errors.EmptyDataError:
        return pd.DataFrame(columns=columns or [])
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6564', _suppressed_exc)
        return pd.DataFrame(columns=columns or [])
    return normalize_optimization_frame(existing_df, columns)


def save_optimization_leaderboard_batch(rows, columns=None, max_rows=None, min_trades=None):
    max_rows = get_optimization_leaderboard_limit(max_rows)
    new_df = normalize_optimization_frame(pd.DataFrame(rows), columns)
    new_df = filter_optimization_min_trades(new_df, min_trades)
    if new_df.empty:
        return 0
    with CSV_WRITE_LOCK:
        existing_df = read_optimization_frame_for_write(OPT_EXPORT_FILE, columns)
        combined_df = pd.concat([existing_df, new_df], ignore_index=True)
        combined_df = normalize_optimization_frame(combined_df, columns)
        sort_col = get_optimization_sort_column(combined_df)
        top_df = combined_df.sort_values(sort_col, ascending=False).head(max_rows).reset_index(drop=True)
        tmp_filename = f"{OPT_EXPORT_FILE}.tmp"
        top_df.to_csv(tmp_filename, index=False)
        os.replace(tmp_filename, OPT_EXPORT_FILE)
    try:
        cached_top_optimization_frame.clear()
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6586', _suppressed_exc)
        pass
    return len(top_df)
