@st.cache_data(ttl=3600, show_spinner=False)
def fetch_kucoin_usdt_coin_options():
    try:
        public_exchange = ccxt.kucoin({"enableRateLimit": True, "timeout": 20000})
        markets = public_exchange.load_markets()
        coins = []
        blocked_suffixes = ("3L", "3S", "UP", "DOWN", "BULL", "BEAR")
        for symbol, market in markets.items():
            try:
                if market.get("quote") != "USDT":
                    continue
                if not market.get("spot", True):
                    continue
                if market.get("active") is False:
                    continue
                base = str(market.get("base", "")).upper().strip()
                if not base or base == "USDT" or any(base.endswith(suffix) for suffix in blocked_suffixes):
                    continue
                if base not in coins:
                    coins.append(base)
            except Exception as _suppressed_exc:
                _log_suppressed_exception('bare_except_L6612', _suppressed_exc)
                continue
        ordered = []
        for coin in DEFAULT_SCAN_COIN_UNIVERSE_LIST:
            if coin in coins and coin not in ordered:
                ordered.append(coin)
        for coin in sorted(coins):
            if coin not in ordered:
                ordered.append(coin)
        return ordered or list(DEFAULT_SCAN_COIN_UNIVERSE_LIST)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6622', _suppressed_exc)
        return list(DEFAULT_SCAN_COIN_UNIVERSE_LIST)


def get_coin_options_for_ui(*extra_sources):
    coins = []
    try:
        coins.extend(normalize_coin_symbol_list(st.session_state.get("kucoin_coin_options", [])))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6630', _suppressed_exc)
        pass
    coins.extend(normalize_coin_symbol_list(DEFAULT_SCAN_COIN_UNIVERSE_LIST))
    for source in extra_sources:
        coins.extend(normalize_coin_symbol_list(source))

    ordered = []
    for coin in DEFAULT_SCAN_COIN_UNIVERSE_LIST:
        if coin in coins and coin not in ordered:
            ordered.append(coin)
    for coin in sorted(set(coins)):
        if coin not in ordered:
            ordered.append(coin)
    return ordered


