def append_event_log(text_line):
    try:
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        clean_lines = str(text_line).splitlines() or [str(text_line)]
        with EVENT_LOG_LOCK:
            with open(EVENT_LOG_FILE, "a", encoding="utf-8") as f:
                for line in clean_lines:
                    f.write(f"[{timestamp}] {line}\n")
        try:
            if has_streamlit_run_context():
                st.session_state["event_log_just_cleared"] = False
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L6672', _suppressed_exc)
            pass
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L6674', _suppressed_exc)
        pass

