def validate_ohlcv_dataframe(df, symbol="", timeframe="", min_rows=60):
    """Validate and clean OHLCV data before indicators/backtests use it."""
    required_cols = ["timestamp", "open", "high", "low", "close", "volume"]
    issues = []
    try:
        if df is None or not isinstance(df, pd.DataFrame) or df.empty:
            return False, ["empty_ohlcv"], pd.DataFrame(columns=required_cols)
        missing_cols = [col for col in required_cols if col not in df.columns]
        if missing_cols:
            return False, [f"missing_columns:{','.join(missing_cols)}"], pd.DataFrame(columns=required_cols)

        cleaned = df.loc[:, required_cols].copy()
        for col in required_cols:
            cleaned[col] = pd.to_numeric(cleaned[col], errors="coerce")
        original_len = len(cleaned)
        cleaned = cleaned.dropna(subset=["timestamp"]).sort_values("timestamp")
        duplicate_count = int(cleaned["timestamp"].duplicated().sum())
        if duplicate_count:
            cleaned = cleaned.drop_duplicates("timestamp", keep="last")
            duplicate_ratio = duplicate_count / max(original_len, 1)
            if duplicate_ratio > 0.02:
                issues.append(f"duplicate_timestamps:{duplicate_count}")

        numeric_cols = ["open", "high", "low", "close", "volume"]
        invalid_numeric_mask = ~np.isfinite(cleaned[numeric_cols]).all(axis=1)
        invalid_price_mask = (
            (cleaned["open"] <= 0)
            | (cleaned["high"] <= 0)
            | (cleaned["low"] <= 0)
            | (cleaned["close"] <= 0)
            | (cleaned["high"] < cleaned["low"])
        )
        invalid_rows = int((invalid_numeric_mask | invalid_price_mask).sum())
        if invalid_rows:
            issues.append(f"invalid_ohlcv_rows:{invalid_rows}")
            cleaned = cleaned.loc[~(invalid_numeric_mask | invalid_price_mask)].copy()

        if len(cleaned) < int(min_rows):
            issues.append(f"too_few_rows:{len(cleaned)}/{int(min_rows)}")

        if not cleaned.empty:
            zero_volume_ratio = float((cleaned["volume"] <= 0).mean())
            if zero_volume_ratio > 0.90:
                issues.append(f"zero_volume_ratio:{zero_volume_ratio:.2f}")
            if len(cleaned) > 2:
                non_positive_deltas = int((cleaned["timestamp"].diff().dropna() <= 0).sum())
                if non_positive_deltas:
                    issues.append(f"non_monotonic_timestamps:{non_positive_deltas}")

        ok = len(cleaned) >= int(min_rows) and not any(
            item.startswith(("missing_columns", "too_few_rows")) for item in issues
        )
        return bool(ok), issues, cleaned.reset_index(drop=True)
    except Exception as _suppressed_exc:
        _log_suppressed_exception("validate_ohlcv_dataframe", _suppressed_exc)
        return False, [f"validation_exception:{_suppressed_exc}"], pd.DataFrame(columns=required_cols)


