def _format_position_age(minutes, english=False):
    minutes = _safe_float(minutes, 0.0)
    if minutes >= 900000:
        return "unknown" if english else "okänd"
    if minutes < 60:
        unit = "min" if english else "min"
        return f"{minutes:.0f} {unit}"
    hours = minutes / 60.0
    if hours < 48:
        return f"{hours:.1f} h"
    days = hours / 24.0
    return f"{days:.1f} d"


