    existing_cfg = load_bot_config()
    opt_bal = st.session_state.get("opt_balance_input", float(st.session_state.get("opt_balance_val", 295.74)))
    opt_tf = st.session_state.get("opt_tf_input", ["1h"]) # Spara som lista
