def _parse_iso_datetime(value, default=None):
    try:
        if isinstance(value, datetime):
            return value
        if value:
            return datetime.fromisoformat(str(value))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L8644', _suppressed_exc)
        pass
    return default


