def load_portfolio_snapshots():
    try:
        if not os.path.exists(PORTFOLIO_SNAPSHOT_FILE):
            return []
        with open(PORTFOLIO_SNAPSHOT_FILE, "r", encoding="utf-8-sig") as f:
            rows = json.load(f)
        if not isinstance(rows, list):
            return []
        clean_rows = []
        for row in rows:
            if not isinstance(row, dict):
                continue
            ts_raw = row.get("timestamp")
            total_value = _safe_float(row.get("total_value"), None)
            if not ts_raw or total_value is None:
                continue
            try:
                datetime.fromisoformat(str(ts_raw))
                clean_rows.append({"timestamp": str(ts_raw), "total_value": float(total_value)})
            except Exception as _suppressed_exc:
                _log_suppressed_exception('bare_except_L8682', _suppressed_exc)
                continue
        return clean_rows
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L8685', _suppressed_exc)
        return []


def save_portfolio_snapshots(rows):
    try:
        atomic_write_json_file(PORTFOLIO_SNAPSHOT_FILE, rows[-500:], indent=2)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L8692', _suppressed_exc)
        pass


def record_portfolio_snapshot(total_value, timestamp=None):
    timestamp = timestamp or datetime.now()
    total_value = _safe_float(total_value, 0.0)
    if total_value <= 0:
        return
    rows = load_portfolio_snapshots()
    cutoff = timestamp - timedelta(hours=72)
    kept = []
    for row in rows:
        try:
            if datetime.fromisoformat(row["timestamp"]) >= cutoff:
                kept.append(row)
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L8708', _suppressed_exc)
            pass
    kept.append({"timestamp": timestamp.isoformat(timespec="seconds"), "total_value": total_value})
    save_portfolio_snapshots(kept)


def get_portfolio_delta_reference(total_value, hours=24):
    total_value = _safe_float(total_value, 0.0)
    rows = load_portfolio_snapshots()
    if not rows or total_value <= 0:
        return None
    target_time = datetime.now() - timedelta(hours=hours)
    parsed_rows = []
    for row in rows:
        try:
            parsed_rows.append((datetime.fromisoformat(row["timestamp"]), _safe_float(row["total_value"])))
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L8724', _suppressed_exc)
            pass
    if not parsed_rows:
        return None
    older_rows = [row for row in parsed_rows if row[0] <= target_time]
    reference_time, reference_value = max(older_rows, key=lambda row: row[0]) if older_rows else min(parsed_rows, key=lambda row: row[0])
    if reference_value <= 0:
        return None
    delta_usdt = total_value - reference_value
    delta_pct = (delta_usdt / reference_value) * 100
    return {
        "reference_time": reference_time,
        "reference_value": reference_value,
        "delta_usdt": delta_usdt,
        "delta_pct": delta_pct
    }


def get_live_wallet_snapshot():
    snapshot = {
        "holdings": [],
        "usdt_free": _safe_float(st.session_state.get("live_usdt", st.session_state.get("usdt_balance", 0.0))),
        "crypto_value": _safe_float(st.session_state.get("live_crypto", 0.0)),
        "total_value": 0.0,
        "prices": {},
        "kcs": st.session_state.get("kcs_balance_snapshot", {}),
        "error": None
    }

    if globals().get('API_CONNECTION_OK') and globals().get('exchange') is not None:
        try:
            bal = kucoin_fetch_balance(globals()['exchange'])
            free_map = bal.get('free', {}) if isinstance(bal, dict) else {}
            total_map = bal.get('total', {}) if isinstance(bal, dict) else {}
            usdt_free = _safe_float(free_map.get('USDT', bal.get('USDT', {}).get('free', 0.0) if isinstance(bal.get('USDT', {}), dict) else 0.0))

            holdings = []
            crypto_value = 0.0
            for asset, raw_qty in total_map.items():
                asset = str(asset).upper()
                qty = _safe_float(raw_qty)
                if asset == "USDT" or qty <= 0:
                    continue
                try:
                    ticker = globals()['exchange'].fetch_ticker(f"{asset}/USDT")
                    price = _safe_float(ticker.get('last', ticker.get('close', 0.0)))
                    value = qty * price
                    snapshot["prices"][asset] = price
                    holdings.append({"asset": asset, "qty": qty, "price": price, "value": value})
                    crypto_value += value
                except Exception as _suppressed_exc:
                    _log_suppressed_exception('bare_except_L8773', _suppressed_exc)
                    holdings.append({"asset": asset, "qty": qty, "price": 0.0, "value": 0.0})

            snapshot["holdings"] = holdings
            snapshot["usdt_free"] = usdt_free
            snapshot["crypto_value"] = crypto_value
            snapshot["total_value"] = usdt_free + crypto_value
            snapshot["kcs"] = build_kcs_balance_snapshot(bal, globals().get('exchange'), include_price=True)
            st.session_state.kcs_balance_snapshot = snapshot["kcs"]
        except Exception as e:
            _log_suppressed_exception('typed_except_L8988_Exception', e)
            snapshot["error"] = str(e)

    if snapshot["total_value"] <= 0:
        snapshot["total_value"] = snapshot["usdt_free"] + snapshot["crypto_value"]

    try:
        st.session_state.usdt_balance = snapshot["usdt_free"]
        st.session_state.live_usdt = snapshot["usdt_free"]
        st.session_state.live_crypto = snapshot["crypto_value"]
        st.session_state.live_total_value = snapshot["total_value"]
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L8791', _suppressed_exc)
        pass

    return snapshot


def format_wallet_lines(snapshot, language=None):
    english = is_english_language(language)
    lines = []
    for item in snapshot.get("holdings", []):
        if _safe_float(item.get("qty")) > 0:
            asset = item.get("asset", "")
            lines.append(f"• {_coin_icon(asset)} {asset}: {_fmt_qty(item.get('qty'))} = {_fmt_usdt(item.get('value'))} USDT")
    free_label = "Free balance" if english else "Ledigt saldo"
    total_label = "Total portfolio value" if english else "Totalt portföljvärde"
    fallback_label = "Wallet snapshot fallback" if english else "Wallet-snapshot fallback"
    lines.append(f"• 💵 USDT: {_fmt_usdt(snapshot.get('usdt_free'))} ({free_label})")
    kcs_snapshot = snapshot.get("kcs", {})
    if isinstance(kcs_snapshot, dict) and kcs_snapshot.get("kcs_discount_enabled"):
        reserve_word = "OK" if kcs_snapshot.get("reserve_ok") else ("LOW" if english else "LÅG")
        lines.append(f"• 💸 KCS: {_fmt_qty(kcs_snapshot.get('kcs_total'))} ≈ {_fmt_usdt(kcs_snapshot.get('kcs_value_usdt'))} USDT ({reserve_word})")
    lines.append(f"📈 {total_label}: {_fmt_usdt(snapshot.get('total_value'))} USDT")
    if snapshot.get("error"):
        lines.append(f"⚠️ {fallback_label}: {snapshot['error']}")
    return lines


def get_recent_trade_activity(period_start, period_end, language=None):
    english = is_english_language(language)
    trade_lines = []
    trades_count = 0
    if not os.path.exists(HISTORY_FILE):
        return trades_count, trade_lines

    try:
        df = pd.read_csv(HISTORY_FILE)
        if df.empty or 'Tid' not in df.columns:
            return trades_count, trade_lines
        df['Tid'] = pd.to_datetime(df['Tid'], errors='coerce')
        recent = df[(df['Tid'] >= period_start) & (df['Tid'] <= period_end)].dropna(subset=['Tid']).sort_values('Tid')
        trades_count = len(recent)
        for _, row in recent.iterrows():
            typ = str(row.get('Typ', '')).upper()
            symbol = str(row.get('Symbol', ''))
            coin = symbol.split('/')[0].upper() if '/' in symbol else symbol.upper()
            amount = _safe_float(row.get('Antal'))
            price = _safe_float(row.get('Pris'))
            total = _safe_float(row.get('Totalt_USDT'))
            if price <= 0 and amount > 0 and total > 0:
                price = total / amount
            if price <= 0 and total > 0:
                price = _fetch_symbol_price(symbol)
            if amount <= 0 and price > 0 and total > 0:
                amount = total / price
            outcome = str(row.get('Utfall', 'LIVE'))
            row_mode_badge = get_trading_mode_badge(row.get("Trading_Mode", get_active_trading_mode()))
            if typ == "BUY":
                side_label = "BUY" if english else "KÖP"
                stake_label = "Stake" if english else "Insats"
                trade_lines.append(f"🛒 [{row_mode_badge}] {side_label}: {_fmt_qty(amount)} {coin} @ {_fmt_usdt(price)} USDT | {stake_label}: {_fmt_usdt(total)} USDT")
            elif typ == "SELL":
                side_label = "SELL" if english else "SÄLJ"
                outcome_label = "Outcome" if english else "Utfall"
                if english:
                    outcome = outcome.replace("avgift", "fee").replace("Avgift", "Fee")
                trade_lines.append(f"💰 [{row_mode_badge}] {side_label}: {_fmt_qty(amount)} {coin} @ {_fmt_usdt(price)} USDT | {outcome_label}: {outcome}")
    except Exception as e:
        _log_suppressed_exception('typed_except_L9062_Exception', e)
        error_label = "Could not read trade history" if english else "Kunde inte läsa tradehistorik"
        trade_lines.append(f"⚠️ {error_label}: {e}")

    return trades_count, trade_lines


def get_live_position_lines(snapshot=None, trading_mode=None, language=None):
    english = is_english_language(language)
    snapshot = snapshot or get_live_wallet_snapshot()
    price_map = dict(snapshot.get("prices", {}))
    position_lines = []
    mode_filter = normalize_trading_mode(trading_mode) if trading_mode is not None else None

    for _, position in load_open_positions().items():
        row_mode = normalize_trading_mode(position.get("trading_mode", "swing"))
        if mode_filter is not None and row_mode != mode_filter:
            continue
        coin = _normalize_position_coin(position.get("coin"))
        entry_price = _safe_float(position.get("buy_price", 0.0))
        current_price = _safe_float(price_map.get(coin, 0.0))
        if current_price <= 0 and globals().get('API_CONNECTION_OK') and globals().get('exchange') is not None:
            try:
                ticker = globals()['exchange'].fetch_ticker(f"{coin}/USDT")
                current_price = _safe_float(ticker.get('last', ticker.get('close', 0.0)))
            except Exception as _suppressed_exc:
                _log_suppressed_exception('bare_except_L8878', _suppressed_exc)
                current_price = 0.0

        if entry_price > 0 and current_price > 0:
            pnl_pct = ((current_price - entry_price) / entry_price) * 100
            pnl_icon = "🟢" if pnl_pct >= 0 else "🔴"
            buy_label = "Buy" if english else "Köpkurs"
            now_label = "Now" if english else "Nu"
            change_label = "Change" if english else "Utveckling"
            position_lines.append(
                f"• [{get_trading_mode_badge(row_mode)}] {_coin_icon(coin)} {coin}/USDT: {buy_label}: {_fmt_usdt(entry_price)} | {now_label}: {_fmt_usdt(current_price)} | {change_label}: {pnl_icon} {pnl_pct:+.2f}%"
            )
        elif entry_price > 0:
            buy_label = "Buy" if english else "Köpkurs"
            now_label = "Now" if english else "Nu"
            change_label = "Change" if english else "Utveckling"
            missing_label = "missing" if english else "saknas"
            unknown_label = "unknown" if english else "okänd"
            position_lines.append(f"• [{get_trading_mode_badge(row_mode)}] {_coin_icon(coin)} {coin}/USDT: {buy_label}: {_fmt_usdt(entry_price)} | {now_label}: {missing_label} | {change_label}: {unknown_label}")

    no_positions = "No open live positions registered." if english else "Inga öppna live-positioner registrerade."
    return position_lines or [f"• 💤 {no_positions}"]


def build_status_report(interval_hours, period_start, period_end, snapshot, previous_total_value=None, delta_24h=None, language=None):
    language = normalize_ui_language(language if language is not None else get_notification_language())
    english = is_english_language(language)
    mode_label = get_active_trading_mode_summary(language)
    total_value = _safe_float(snapshot.get("total_value"))
    if previous_total_value is None:
        previous_total_value = total_value
    previous_total_value = _safe_float(previous_total_value, total_value)
    delta_usdt = total_value - previous_total_value
    delta_pct = (delta_usdt / previous_total_value * 100) if previous_total_value > 0 else 0.0
    delta_icon = "🟢" if delta_usdt >= 0 else "🔴"
    if delta_24h:
        delta_24h_usdt = _safe_float(delta_24h.get("delta_usdt"))
        delta_24h_pct = _safe_float(delta_24h.get("delta_pct"))
        delta_24h_icon = "🟢" if delta_24h_usdt >= 0 else "🔴"
        delta_24h_label = "Last 24h" if english else "Senaste 24h"
        delta_24h_line = f"• {delta_24h_label}: {delta_24h_icon} {delta_24h_usdt:+.2f} USDT ({delta_24h_pct:+.2f}%)"
    else:
        delta_24h_line = "• Last 24h: collecting comparison data." if english else "• Senaste 24h: samlar jämförelsedata."

    trades_count, trade_lines = get_recent_trade_activity(period_start, period_end, language=language)
    if not trade_lines:
        trade_lines = ["💤 No new trades executed during this period." if english else "💤 Inga nya trades utförda under denna period."]

    position_lines = get_live_position_lines(snapshot, language=language)
    status_title = "STATUS REPORT" if english else "STATUSRAPPORT"
    mode_label_title = "Trading mode" if english else "Tradingläge"
    interval_label = "Interval" if english else "Intervall"
    time_label = "Time" if english else "Tid"
    wallet_title = "WALLET OVERVIEW (HOLDINGS)" if english else "PLÅNBOKSÖVERSIKT (HÅLLNINGAR)"
    net_title = "NET RETURN" if english else "NETTOAVKASTNING"
    since_label = "Since previous update" if english else "Sedan förra uppdateringen"
    activity_title = "ACTIVITY THIS PERIOD" if english else "AKTIVITET SENASTE PERIODEN"
    trade_count_label = "Executed trades" if english else "Antal utförda trades"
    trade_count_unit = "pcs" if english else "st"
    positions_title = "LIVE POSITION DEVELOPMENT (SINCE BUY)" if english else "POSITIONER LIVE-UTVECKLING (SEDAN KÖP)"
    msg = (
        f"📊 {BOT_DISPLAY_NAME} BOT {status_title}\n"
        f"🎛 {mode_label_title}: {mode_label}\n"
        f"⏱ {interval_label}: {interval_hours:g}h | {time_label}: {period_end.strftime('%Y-%m-%d %H:%M')}\n\n"
        f"💰 {wallet_title}:\n"
        + "\n".join(format_wallet_lines(snapshot, language=language)) +
        f"\n\n🔄 {net_title}:\n"
        f"• {since_label}: {delta_icon} {delta_usdt:+.2f} USDT ({delta_pct:+.2f}%)\n"
        f"{delta_24h_line}\n\n"
        f"⚡ {activity_title}:\n"
        f"• {trade_count_label}: {trades_count} {trade_count_unit}\n"
        + "\n".join(trade_lines) +
        f"\n\n📋 {positions_title}:\n"
        + "\n".join(position_lines)
    )
    return msg, total_value


