def send_periodic_status_report(force=False):
    with TELEGRAM_REPORT_LOCK:
        now = datetime.now()
        interval_hours = get_report_interval_hours(2.0)
        state = load_telegram_report_state()
        last_report = _parse_iso_datetime(state.get("last_report"))

        # Första gången skickas en basrapport direkt. Därefter styr filen intervallet,
        # oberoende av Streamlit-reruns, trades eller vilken enhet som tittar på UI:t.
        if last_report is None:
            last_report = now - timedelta(hours=interval_hours)

        if not force and now - last_report < timedelta(hours=interval_hours):
            return False

        retry_after = _parse_iso_datetime(state.get("retry_after"))
        if retry_after is None:
            retry_after = _parse_iso_datetime(st.session_state.get("telegram_report_retry_after"))
        if not force and isinstance(retry_after, datetime) and now < retry_after:
            return False

        snapshot = get_live_wallet_snapshot()
        previous_total = st.session_state.get("telegram_previous_total_value", state.get("previous_total_value"))
        if previous_total is None:
            previous_total = snapshot.get("total_value", 0.0)

        delta_24h = get_portfolio_delta_reference(snapshot.get("total_value"), hours=24)
        msg_body, current_total = build_status_report(interval_hours, last_report, now, snapshot, previous_total, delta_24h=delta_24h)
        ok, send_msg = send_telegram_message(msg_body, category="status", force=force)

        record_portfolio_snapshot(current_total, now)

        append_system_event(msg_body)
        if ok:
            st.session_state.last_telegram_report = now
            st.session_state.telegram_previous_total_value = current_total
            st.session_state.telegram_report_retry_after = None
            save_telegram_report_state({
                "last_report": now.isoformat(),
                "last_report_display": now.strftime("%Y-%m-%d %H:%M:%S"),
                "last_attempt": now.isoformat(),
                "last_attempt_display": now.strftime("%Y-%m-%d %H:%M:%S"),
                "interval_hours": interval_hours,
                "previous_total_value": current_total,
                "retry_after": None,
                "last_status": "sent",
                "last_message": "OK"
            })
            append_system_event(f"TELEGRAM: Tidsrapport skickad ({interval_hours:g}h).")
        else:
            retry_time = now + timedelta(minutes=5)
            st.session_state.telegram_report_retry_after = retry_time
            state.update({
                "retry_after": retry_time.isoformat(),
                "last_attempt": now.isoformat(),
                "last_attempt_display": now.strftime("%Y-%m-%d %H:%M:%S"),
                "interval_hours": interval_hours,
                "last_status": "failed",
                "last_message": str(send_msg),
                "previous_total_value": previous_total
            })
            save_telegram_report_state(state)
            append_system_event(f"TELEGRAM: Tidsrapport kunde inte skickas: {send_msg}")
        return ok


def send_optimization_completion_report(final_status_text):
    language = get_notification_language()
    english = is_english_language(language)
    final_status_text = str(final_status_text or "").strip()
    if not final_status_text:
        return False
    terminal_markers = ("Slutförd", "Skanning klar", "stoppades", "avbröts", "Kritiskt", "Critical")
    if not any(marker in final_status_text for marker in terminal_markers):
        return False

    try:
        if os.path.exists(OPT_EXPORT_FILE) and os.path.getsize(OPT_EXPORT_FILE) > 0:
            result_df = read_top_optimization_frame(OPT_EXPORT_FILE, get_optimization_leaderboard_limit(), OPTIMIZATION_EXPORT_COLUMNS)
        else:
            result_df = pd.DataFrame(columns=OPTIMIZATION_EXPORT_COLUMNS)
        result_df = normalize_optimization_frame(result_df, OPTIMIZATION_EXPORT_COLUMNS)
        if not result_df.empty:
            sort_col = get_optimization_sort_column(result_df)
            result_df = result_df.sort_values(sort_col, ascending=False).reset_index(drop=True)
    except Exception as csv_err:
        _log_suppressed_exception('typed_except_L9306_Exception', csv_err)
        result_df = pd.DataFrame(columns=OPTIMIZATION_EXPORT_COLUMNS)
        final_status_text = f"{final_status_text}\n⚠️ CSV: {csv_err}"

    title = "BACKGROUND SCAN FINISHED" if english else "BAKGRUNDSSKANNING KLAR"
    status_label = "Status" if english else "Status"
    time_label = "Time" if english else "Tid"
    file_label = "File" if english else "Fil"
    rows_label = "Rows in leaderboard" if english else "Rader i leaderboard"
    top_label = "UI-compatible Top 3 versus live" if english else "UI-kompatibel Top 3 mot live"
    no_rows = "No strategy rows were saved. Lower Min trades or broaden the scan ranges." if english else "Inga strategirader sparades. Sänk Min trades eller bredda skannerns intervall."

    top_lines = []
    suggestions = get_top3_display_suggestions(limit=3, better_only=False)
    if suggestions:
        for item in suggestions:
            row = item.get("row", {})
            mode_badge = item.get("mode_badge", get_trading_mode_badge(row.get("Trading_Mode", "swing")))
            mode_rank = int(_safe_float(item.get("mode_rank", item.get("rank", 0)), item.get("rank", 0)))
            profit = _safe_float(row.get("Profit_USDT", item.get("profit", 0.0)))
            diff_profit = _safe_float(item.get("diff_profit", 0.0))
            diff_pct = _safe_float(item.get("diff_pct", 0.0))
            quality = str(item.get("quality_vs_live", "") or "").strip()
            fitness = _safe_float(row.get("Fitness_Score", profit))
            sharpe = _safe_float(row.get("Sharpe_Ratio", 0.0))
            sortino = _safe_float(row.get("Sortino_Ratio", 0.0))
            dd = _safe_float(row.get("Max_Drawdown_Pct", 0.0))
            trades = int(_safe_float(row.get("Total_Trades", 0), 0))
            timeframe = str(row.get("selected_timeframe", ""))
            rsi = int(_safe_float(row.get("high_risk_factor", 0), 0))
            ui_place = f"UI {mode_badge} #{mode_rank}"
            diff_label = "VERSUS LIVE" if english else "MOT LIVE"
            new_strategy_label = "NEW STRATEGY" if english else "NY STRATEGI"
            top_lines.append(
                f"#{item.get('rank', mode_rank)} [{mode_badge}] {ui_place}\n"
                f"• {diff_label}: {diff_profit:+.2f} USDT ({diff_pct:+.2f}%) {quality}\n"
                f"• {new_strategy_label}: {profit:+.2f} USDT\n"
                f"• Fit {fitness:.0f} | Sharpe {sharpe:.2f} | Sortino {sortino:.2f} | DD {dd:.2f}%\n"
                f"• Trades {trades} | RSI {rsi} | TF {timeframe}"
            )
    else:
        top_lines.append(no_rows)

    top_separator = "\n\n--------------------\n\n"
    top_block = top_separator.join(top_lines)

    message = (
        f"✅ {BOT_DISPLAY_NAME} {title}\n"
        f"⏱ {time_label}: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}\n"
        f"📌 {status_label}: {final_status_text}\n"
        f"📄 {file_label}: {os.path.basename(OPT_EXPORT_FILE)}\n"
        f"📊 {rows_label}: {len(result_df)}\n\n"
        f"🏆 {top_label}:\n\n" + top_block
    )
    ok, send_msg = send_telegram_message(message, category="scan")
    append_system_event(message)
    if ok:
        append_system_event("TELEGRAM: Scan completion report sent." if english else "TELEGRAM: Skanningssummering skickad.")
    else:
        append_system_event(f"TELEGRAM: Scan completion report failed: {send_msg}" if english else f"TELEGRAM: Skanningssummering kunde inte skickas: {send_msg}")
    return ok


def _strategy_bool(value):
    if isinstance(value, str):
        return value.strip().lower() in ("true", "1", "yes", "ja", "✅")
    return bool(value)


def _parse_percent_csv(raw):
    values = []
    for part in str(raw or "").split(","):
        part = part.strip().replace("%", "").replace(" ", "")
        if not part:
            continue
        try:
            values.append(int(round(float(part.replace(",", ".")))))
        except Exception as _suppressed_exc:
            _log_suppressed_exception('bare_except_L9176', _suppressed_exc)
            pass
    return values


def _even_percent_split(count):
    try:
        count = int(count)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9184', _suppressed_exc)
        count = 0
    if count <= 0:
        return []
    base = 100 // count
    remainder = 100 - (base * count)
    return [base + (1 if idx < remainder else 0) for idx in range(count)]


def get_strategy_assets_and_allocations(row, fallback_pcts_raw=None):
    try:
        raw_coins = row.get('Valutor', 'BTC,ETH,LTC,XRP,XMR')
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9196', _suppressed_exc)
        raw_coins = 'BTC,ETH,LTC,XRP,XMR'
    coins = normalize_coin_symbol_list(raw_coins)

    try:
        raw_pcts = row.get('Portfolio_Pcts', row.get('Portfoljfordelning_Procent', ""))
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9202', _suppressed_exc)
        raw_pcts = ""
    try:
        if pd.isna(raw_pcts):
            raw_pcts = ""
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9207', _suppressed_exc)
        pass

    pcts = _parse_percent_csv(raw_pcts)
    if len(pcts) != len(coins):
        if fallback_pcts_raw is None:
            try:
                fallback_pcts_raw = st.session_state.get("opt_pcts_input", load_bot_config().get("opt_pcts_raw", ""))
            except Exception as _suppressed_exc:
                _log_suppressed_exception('bare_except_L9215', _suppressed_exc)
                fallback_pcts_raw = ""
        pcts = _parse_percent_csv(fallback_pcts_raw)
    if len(pcts) != len(coins):
        pcts = _even_percent_split(len(coins))

    return coins, pcts


def format_strategy_assets_line(coins, pcts):
    if not coins:
        return "Inga valutor angivna"
    return ", ".join(f"{coin} {pct}%" for coin, pct in zip(coins, pcts))


