def get_live_reference_profit(opt_base_cap, max_age_seconds=30):
    now_ts = time.time()
    signature = get_live_config_signature(opt_base_cap)
    if (
        "cached_live_profit" in st.session_state and
        st.session_state.get("cached_live_profit_signature") == signature and
        now_ts - float(st.session_state.get("last_live_backtest_time", 0.0)) <= max_age_seconds
    ):
        return _safe_float(st.session_state.cached_live_profit)

    try:
        live_res = run_flexible_backtest(
            is_mockup=True,
            mock_allocations=st.session_state.allocations,
            mock_tf=st.session_state.selected_timeframe,
            mock_filter=st.session_state.use_trend_filter,
            mock_bb=st.session_state.use_bb_filter,
            mock_macd=st.session_state.use_macd_filter,
            mock_dynamic=st.session_state.dynamic_sizing,
            mock_start_bal=opt_base_cap,
            mock_rsi=st.session_state.high_risk_factor,
            mock_tp=st.session_state.take_profit_pct,
            mock_sl=st.session_state.stop_loss_pct,
            mock_vol_filter=st.session_state.use_volume_filter,
            mock_ai_block=st.session_state.use_ai_block_bear,
            mock_sl_strat=st.session_state.stop_loss_strategy,
            mock_atr_mult=st.session_state.atr_multiplier,
            mock_trailing=st.session_state.get('use_trailing_stop', True),
            mock_trail_activation=st.session_state.get('trailing_activation_pct', 2.0),
            mock_trail_distance=st.session_state.get('trailing_distance_pct', 1.5),
            mock_grid=st.session_state.get('use_grid_trading', False),
            mock_grid_spacing=st.session_state.get('grid_spacing_pct', 1.5),
            mock_grid_levels=st.session_state.get('grid_levels', 3),
            mock_sent_drop_threshold=st.session_state.get('sentiment_drop_threshold_pct', -4.0),
            mock_sent_rsi_threshold=st.session_state.get('sentiment_rsi_threshold', 35.0),
            mock_scan_days=get_opt_scan_days(),
            mock_take_profit_strategy=st.session_state.get('take_profit_strategy', 'Procent'),
            mock_tp_atr_mult=st.session_state.get('take_profit_atr_mult', 2.0),
            mock_max_bars=st.session_state.get('max_bars_in_trade', 96),
            mock_market_regime_mode=st.session_state.get('market_regime_mode', 'Adaptive'),
            mock_cmf_threshold=st.session_state.get('cmf_threshold', -0.05),
            mock_volume_spike_mult=st.session_state.get('volume_spike_mult', 1.0),
            mock_bbw_threshold=st.session_state.get('bbw_threshold', 0.0),
            mock_squeeze_required=st.session_state.get('squeeze_required', False),
            mock_session_start_hour=st.session_state.get('session_start_hour', 0),
            mock_session_end_hour=st.session_state.get('session_end_hour', 23),
            mock_weekday_mask=st.session_state.get('weekday_mask', 127),
            mock_htf_filter=st.session_state.get('htf_filter', False)
        )
        if isinstance(live_res, dict) and 'final' in live_res:
            st.session_state.cached_live_profit = round(live_res['final'] - live_res['start_bal'], 2)
        else:
            st.session_state.cached_live_profit = 0.0
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9938', _suppressed_exc)
        st.session_state.cached_live_profit = 0.0

    st.session_state.last_live_backtest_time = now_ts
    st.session_state.cached_live_profit_signature = signature
    return _safe_float(st.session_state.cached_live_profit)


def resolve_live_reference_profit(df_live_sorted, opt_base_cap, allow_backtest=True):
    try:
        for _, row in df_live_sorted.iterrows():
            if _row_matches_live_config(row):
                live_profit = _safe_float(row.get('Profit_USDT'))
                st.session_state.cached_live_profit = live_profit
                st.session_state.cached_live_profit_signature = get_live_config_signature(opt_base_cap)
                st.session_state.last_live_backtest_time = time.time()
                st.session_state.live_reference_source = "optimization_results.csv"
                return live_profit, "optimization_results.csv"
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9956', _suppressed_exc)
        pass

    if not allow_backtest:
        live_profit = _safe_float(st.session_state.get("cached_live_profit", 0.0))
        st.session_state.live_reference_source = "cached_only_during_scan"
        return live_profit, "cached_only_during_scan"

    live_profit = get_live_reference_profit(opt_base_cap, max_age_seconds=300)
    st.session_state.live_reference_source = "live_backtest_cache"
    return live_profit, "live_backtest_cache"


def get_trade_quality_thresholds(trading_mode=None, scan_days=None):
    mode = normalize_trading_mode(trading_mode or get_active_trading_mode())
    days = _safe_float(scan_days, 0.0)
    if days <= 0:
        days = 30.0 if mode == "day" else 60.0

    if mode == "day":
        bad_lt = max(10, int(round(days * 0.75)))
        okay_lt = max(bad_lt + 1, int(round(days * 2.0)))
        good_lt = max(okay_lt + 1, int(round(days * 5.0)))
    else:
        bad_lt = max(3, int(round(days * 0.08)))
        okay_lt = max(bad_lt + 1, int(round(days * 0.25)))
        good_lt = max(okay_lt + 1, int(round(days * 0.83)))
    return bad_lt, okay_lt, good_lt


def format_trade_quality_benchmarks(trading_mode=None, scan_days=None):
    bad_lt, okay_lt, good_lt = get_trade_quality_thresholds(trading_mode, scan_days)
    return f"🔴 <{bad_lt} | 🟡 {bad_lt}-{okay_lt - 1} | 🟢 {okay_lt}-{good_lt - 1} | 💎 {good_lt}+"


def localize_quality_label(label):
    """Translate compact quality labels used inside dynamic Top 3 cards."""
    text = str(label or "")
    if get_ui_language() != "en":
        return text
    replacements = {
        "Mycket bättre": "Much better",
        "Dåligt": "Poor",
        "Dålig": "Poor",
        "Okej": "Okay",
        "Bra": "Good",
        "Identisk": "Identical",
        "Super": "Excellent",
        "saknas": "missing",
        "bättre": "better",
        "sämre": "worse",
        "likvärdig": "equivalent",
        "identisk": "identical",
    }
    for sv_text, en_text in replacements.items():
        text = text.replace(sv_text, en_text)
    return text


def metric_quality(metric_name, value, trades=None, trading_mode=None, scan_days=None):
    metric = str(metric_name or "").lower()
    value = _safe_float(value, 0.0)
    try:
        trades = int(float(trades)) if trades is not None else None
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L9996', _suppressed_exc)
        trades = None

    if metric == "fitness":
        if value < 0:
            return localize_quality_label("🔴 Dåligt")
        if value < 500:
            return localize_quality_label("🟡 Okej")
        if value < 1500:
            return localize_quality_label("🟢 Bra")
        return localize_quality_label("💎 Super")
    if metric in ("sharpe", "sortino"):
        if value < 0:
            return localize_quality_label("🔴 Dåligt")
        if value < 1:
            return localize_quality_label("🟡 Okej")
        if value < 3:
            return localize_quality_label("🟢 Bra")
        return localize_quality_label("💎 Super")
    if metric == "max_dd":
        if value > 20:
            return localize_quality_label("🔴 Dåligt")
        if value > 10:
            return localize_quality_label("🟡 Okej")
        if value > 3:
            return localize_quality_label("🟢 Bra")
        return localize_quality_label("💎 Super")
    if metric == "winrate":
        if value < 40:
            return localize_quality_label("🔴 Dåligt")
        if value < 50:
            return localize_quality_label("🟡 Okej")
        if value < 65:
            return localize_quality_label("🟢 Bra")
        return localize_quality_label("💎 Super")
    if metric == "trades":
        bad_lt, okay_lt, good_lt = get_trade_quality_thresholds(trading_mode, scan_days)
        if value < bad_lt:
            return localize_quality_label("🔴 Dåligt")
        if value < okay_lt:
            return localize_quality_label("🟡 Okej")
        if value < good_lt:
            return localize_quality_label("🟢 Bra")
        return localize_quality_label("💎 Super")
    if metric == "out_sample":
        if value <= 0:
            return localize_quality_label("🔴 Dåligt")
        if value < 10:
            return localize_quality_label("🟡 Okej")
        if value < 50:
            return localize_quality_label("🟢 Bra")
        return localize_quality_label("💎 Super")
    return ""


def _metric_delta_text(current_value, live_value, decimals=2, lower_is_better=False):
    if live_value is None:
        return "Î” live: missing" if get_ui_language() == "en" else "Î” live: saknas"
    current_value = _safe_float(current_value, 0.0)
    live_value = _safe_float(live_value, 0.0)
    delta = (live_value - current_value) if lower_is_better else (current_value - live_value)
    icon = "🟢" if delta > 0 else ("🔴" if delta < 0 else "⚖️")
    return f"{icon} Î” {delta:+.{decimals}f}"


def classify_strategy_vs_live(diff_profit, diff_pct, is_identical=False):
    diff_profit = _safe_float(diff_profit, 0.0)
    diff_pct = _safe_float(diff_pct, 0.0)
    if is_identical or abs(diff_profit) <= 0.1:
        return localize_quality_label("⚖️ Identisk")
    if diff_profit < 0 or diff_pct < 0:
        return localize_quality_label("🔴 Dålig")
    if diff_pct < 1.0:
        return localize_quality_label("🟡 Okej")
    if diff_pct < 5.0:
        return localize_quality_label("🟢 Bra")
    return localize_quality_label("💎 Mycket bättre")


def _optional_float(value):
    try:
        if value is None:
            return None
        if isinstance(value, str):
            cleaned = value.strip().replace("%", "").replace(",", ".")
            if cleaned == "" or cleaned.lower() in ("none", "null", "nan"):
                return None
            value = cleaned
        result = float(value)
        if not np.isfinite(result):
            return None
        return result
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L10088', _suppressed_exc)
        return None


def save_live_reference_metric_baseline(profit=None, fitness=None, sharpe=None, sortino=None, max_dd=None, signature=None, source="optimization_results.csv", persist=True, mode=None, update_global=True):
    try:
        mode_cfg = normalize_trading_mode(mode or get_active_trading_mode())
        update_global = bool(update_global or mode_cfg == get_active_trading_mode())
        updated_at = datetime.now().isoformat(timespec="seconds")

        reference_profit = _safe_float(profit, _safe_float(st.session_state.get("cached_live_profit", 0.0), 0.0)) if profit is not None else _safe_float(st.session_state.get("cached_live_profit", 0.0), 0.0)
        reference_fitness = _optional_float(fitness) if fitness is not None else _optional_float(st.session_state.get("cached_live_fitness"))
        reference_sharpe = _optional_float(sharpe) if sharpe is not None else _optional_float(st.session_state.get("cached_live_sharpe"))
        reference_sortino = _optional_float(sortino) if sortino is not None else _optional_float(st.session_state.get("cached_live_sortino"))
        reference_max_dd = _optional_float(max_dd) if max_dd is not None else _optional_float(st.session_state.get("cached_live_max_dd"))
        reference_signature = str(signature) if signature is not None else str(st.session_state.get("cached_live_profit_signature", ""))

        if update_global:
            st.session_state.cached_live_profit = reference_profit
            st.session_state.cached_live_fitness = reference_fitness
            st.session_state.cached_live_sharpe = reference_sharpe
            st.session_state.cached_live_sortino = reference_sortino
            st.session_state.cached_live_max_dd = reference_max_dd
            st.session_state.cached_live_profit_signature = reference_signature
            st.session_state.last_live_backtest_time = time.time()
            st.session_state.live_reference_source = source
            st.session_state.live_reference_updated_at = updated_at

        if not persist:
            return

        cfg = load_bot_config()
        next_values = {
            "live_reference_profit": reference_profit,
            "live_reference_fitness": reference_fitness,
            "live_reference_sharpe": reference_sharpe,
            "live_reference_sortino": reference_sortino,
            "live_reference_max_dd": reference_max_dd,
            "live_reference_signature": reference_signature,
            "live_reference_source": source,
            "live_reference_updated_at": updated_at,
            "trading_mode": mode_cfg,
        }
        raw_mode_refs = cfg.get("mode_live_reference", {})
        mode_refs = dict(raw_mode_refs) if isinstance(raw_mode_refs, dict) else {}
        mode_refs[mode_cfg] = dict(next_values)
        stable_keys = [k for k in next_values.keys() if k not in ("live_reference_updated_at", "trading_mode")]
        global_changed = update_global and any(cfg.get(k) != next_values[k] for k in stable_keys)
        mode_refs_changed = cfg.get("mode_live_reference") != mode_refs
        cfg["mode_live_reference"] = mode_refs
        if global_changed:
            cfg.update({k: v for k, v in next_values.items() if k != "trading_mode"})
        if global_changed or mode_refs_changed:
            atomic_write_json_file(CONFIG_FILE, cfg, indent=4)
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L10142', _suppressed_exc)
        pass


def format_live_metric_comparison_line(r_fitness, r_sharpe, r_sortino, r_dd, live_reference_metrics):
    metrics = live_reference_metrics or {}
    english = get_ui_language() == "en"
    items = []
    metric_specs = [
        ("Fitness", r_fitness, metrics.get("fitness"), 0, False, ""),
        ("Sharpe", r_sharpe, metrics.get("sharpe"), 2, False, ""),
        ("Sortino", r_sortino, metrics.get("sortino"), 2, False, ""),
        ("Max DD", r_dd, metrics.get("max_dd"), 2, True, " p.e."),
    ]
    for name, current_value, live_value, decimals, lower_is_better, unit in metric_specs:
        live_value = _optional_float(live_value)
        if live_value is None:
            items.append(f"{name}: {'Î” missing' if english else 'Î” saknas'}")
            continue
        current_value = _safe_float(current_value, 0.0)
        delta = (live_value - current_value) if lower_is_better else (current_value - live_value)
        icon = "🟢" if delta > 0 else ("🔴" if delta < 0 else "⚖️")
        items.append(f"{name}: {icon} {delta:+.{decimals}f}{unit}")
    prefix = "📊 **Risk metrics versus live:** " if english else "📊 **Riskmått mot live:** "
    return prefix + " | ".join(items)


def get_mode_live_reference_metrics_from_config(mode=None, signature=None):
    try:
        mode_cfg = normalize_trading_mode(mode or get_active_trading_mode())
        cfg = load_bot_config()
        mode_refs = cfg.get("mode_live_reference", {})
        if not isinstance(mode_refs, dict):
            return None
        payload = mode_refs.get(mode_cfg, {})
        if not isinstance(payload, dict):
            return None
        if signature is not None and str(payload.get("live_reference_signature", "")) != str(signature):
            return None
        fitness = _optional_float(payload.get("live_reference_fitness"))
        sharpe = _optional_float(payload.get("live_reference_sharpe"))
        sortino = _optional_float(payload.get("live_reference_sortino"))
        max_dd = _optional_float(payload.get("live_reference_max_dd"))
        if all(value is None for value in (fitness, sharpe, sortino, max_dd)):
            return None
        return {
            "profit": _safe_float(payload.get("live_reference_profit", 0.0), 0.0),
            "fitness": fitness,
            "sharpe": sharpe,
            "sortino": sortino,
            "max_dd": max_dd,
            "source": payload.get("live_reference_source", "mode_live_reference"),
        }
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L10193', _suppressed_exc)
        return None


def resolve_live_reference_metrics(df_live_sorted, opt_base_cap, allow_backtest=True):
    metrics = {
        "profit": 0.0, "fitness": None, "sharpe": None, "sortino": None,
        "max_dd": None, "source": "unknown"
    }
    current_signature = get_live_config_signature(opt_base_cap)
    current_mode = get_active_trading_mode()
    try:
        for _, row in df_live_sorted.iterrows():
            if _row_matches_live_config(row):
                metrics.update({
                    "profit": _safe_float(row.get('Profit_USDT')),
                    "fitness": _safe_float(row.get('Fitness_Score')),
                    "sharpe": _safe_float(row.get('Sharpe_Ratio')),
                    "sortino": _safe_float(row.get('Sortino_Ratio')),
                    "max_dd": _safe_float(row.get('Max_Drawdown_Pct')),
                    "source": "optimization_results.csv"
                })
                save_live_reference_metric_baseline(
                    profit=metrics["profit"],
                    fitness=metrics["fitness"],
                    sharpe=metrics["sharpe"],
                    sortino=metrics["sortino"],
                    max_dd=metrics["max_dd"],
                    signature=current_signature,
                    source=metrics["source"],
                    persist=True,
                    mode=current_mode
                )
                save_live_strategy_baseline_snapshot(row, metrics, source=metrics["source"], mode=current_mode)
                return metrics
    except Exception as _suppressed_exc:
        _log_suppressed_exception('bare_except_L10228', _suppressed_exc)
        pass

    snapshot_metrics = get_live_strategy_baseline_metrics_from_snapshot(current_mode)
    if snapshot_metrics:
        save_live_reference_metric_baseline(
            profit=snapshot_metrics["profit"],
            fitness=snapshot_metrics["fitness"],
            sharpe=snapshot_metrics["sharpe"],
            sortino=snapshot_metrics["sortino"],
            max_dd=snapshot_metrics["max_dd"],
            signature=current_signature,
            source=snapshot_metrics.get("source", "live_strategy_baseline.json"),
            persist=True,
            mode=current_mode
        )
        return snapshot_metrics

    saved_mode_metrics = get_mode_live_reference_metrics_from_config(current_mode, current_signature)
    if saved_mode_metrics:
        return saved_mode_metrics
    saved_mode_metrics = get_mode_live_reference_metrics_from_config(current_mode, None)
    if saved_mode_metrics:
        saved_mode_metrics = dict(saved_mode_metrics)
        saved_mode_metrics["source"] = f"{saved_mode_metrics.get('source', 'mode_live_reference')} (senast sparad livebaslinje)"
        return saved_mode_metrics

    live_profit, source = resolve_live_reference_profit(df_live_sorted, opt_base_cap, allow_backtest=allow_backtest)
    cached_signature = st.session_state.get("cached_live_profit_signature", "")
    cached_metrics_valid = cached_signature == current_signature
    metrics.update({
        "profit": live_profit,
        "fitness": st.session_state.get("cached_live_fitness") if cached_metrics_valid else None,
        "sharpe": st.session_state.get("cached_live_sharpe") if cached_metrics_valid else None,
        "sortino": st.session_state.get("cached_live_sortino") if cached_metrics_valid else None,
        "max_dd": st.session_state.get("cached_live_max_dd") if cached_metrics_valid else None,
        "source": source if cached_metrics_valid else f"{source}_profit_only"
    })
    return metrics


