def get_execution_cost_pct(cfg=None):
    settings = get_execution_model_settings(cfg)
    # Spread belastar en rundtur med ungefär halva spreaden per sida.
    per_side_pct = (settings["execution_spread_pct"] / 2.0) + settings["execution_slippage_pct"]
    return max(0.0, float(per_side_pct))


def get_execution_worst_cost_pct(cfg=None):
    settings = get_execution_model_settings(cfg)
    per_side_pct = (settings["execution_spread_pct"] / 2.0) + settings["execution_worst_slippage_pct"]
    return max(0.0, float(per_side_pct))


def apply_execution_price(price, side, cfg=None, worst_case=False):
    price = _safe_float(price, 0.0)
    if price <= 0:
        return 0.0
    cost_pct = get_execution_worst_cost_pct(cfg) if worst_case else get_execution_cost_pct(cfg)
    if str(side).lower() == "buy":
        return price * (1.0 + cost_pct / 100.0)
    return max(0.0, price * (1.0 - cost_pct / 100.0))


def get_roundtrip_cost_pct(cfg=None):
    settings = get_execution_model_settings(cfg)
    fee_rate_pct = get_trade_fee_rate(cfg) * 100.0
    return max(0.0, (fee_rate_pct * 2.0) + settings["execution_spread_pct"] + (settings["execution_slippage_pct"] * 2.0))


def _extract_realized_pnl_usdt_from_utfall(value):
    text = str(value or "")
    match = re.search(r"([+-]?\d+(?:[\.,]\d+)?)\s*USDT", text)
    if not match:
        return 0.0
    return _safe_float(match.group(1).replace(",", "."), 0.0)


def get_realized_pnl_since(mode, since_dt):
    try:
        df = load_trade_history()
        if df is None or df.empty:
            return 0.0
        mode = normalize_trading_mode(mode or get_active_trading_mode())
        if "Trading_Mode" in df.columns:
            df = df[df["Trading_Mode"].fillna(mode).map(lambda item: normalize_trading_mode(item) == mode)]
        if "Typ" in df.columns:
            df = df[df["Typ"].astype(str).str.upper() == "SELL"]
        if df.empty or "Tid" not in df.columns:
            return 0.0
        timestamps = pd.to_datetime(df["Tid"], errors="coerce")
        df = df[timestamps >= pd.Timestamp(since_dt)]
        if df.empty:
            return 0.0
        return float(sum(_extract_realized_pnl_usdt_from_utfall(value) for value in df.get("Utfall", [])))
    except Exception as _suppressed_exc:
        _log_suppressed_exception("get_realized_pnl_since", _suppressed_exc)
        return 0.0


def build_roi_dashboard_summary():
    try:
        df = load_trade_history()
        if df is None or df.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Trades", "Wins", "Losses", "WinRate", "RealizedPnL", "Fees"])
        df = df.copy()
        if "Utfall" in df.columns:
            df = df[~df["Utfall"].astype(str).str.contains("MANUELLT SYSTEMTEST", case=False, na=False)]
        if df.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Trades", "Wins", "Losses", "WinRate", "RealizedPnL", "Fees"])
        mode_series = df["Trading_Mode"] if "Trading_Mode" in df.columns else pd.Series([""] * len(df), index=df.index)
        symbol_series = df["Symbol"] if "Symbol" in df.columns else pd.Series([""] * len(df), index=df.index)
        side_series = df["Typ"] if "Typ" in df.columns else pd.Series([""] * len(df), index=df.index)
        fee_series = df["Fee_USDT"] if "Fee_USDT" in df.columns else pd.Series([0.0] * len(df), index=df.index)
        outcome_series = df["Utfall"] if "Utfall" in df.columns else pd.Series([""] * len(df), index=df.index)
        df["Mode"] = mode_series.map(lambda item: get_trading_mode_badge(normalize_trading_mode(item)))
        df["Coin"] = symbol_series.astype(str).str.upper().str.replace("/USDT", "", regex=False)
        df["Side"] = side_series.astype(str).str.upper()
        df["Fee_USDT_Num"] = pd.to_numeric(fee_series, errors="coerce").fillna(0.0)
        df["PnL_USDT"] = outcome_series.map(_extract_realized_pnl_usdt_from_utfall)
        sells = df[df["Side"] == "SELL"].copy()
        if sells.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Trades", "Wins", "Losses", "WinRate", "RealizedPnL", "Fees"])
        rows = []
        for (mode, coin), group in sells.groupby(["Mode", "Coin"], dropna=False):
            trades = int(len(group))
            wins = int((group["PnL_USDT"] > 0).sum())
            losses = int((group["PnL_USDT"] < 0).sum())
            winrate = (wins / trades * 100.0) if trades else 0.0
            rows.append({
                "Mode": mode or "-",
                "Coin": coin or "-",
                "Trades": trades,
                "Wins": wins,
                "Losses": losses,
                "WinRate": round(winrate, 1),
                "RealizedPnL": round(float(group["PnL_USDT"].sum()), 2),
                "Fees": round(float(group["Fee_USDT_Num"].sum()), 2),
            })
        out = pd.DataFrame(rows)
        if out.empty:
            return out
        return out.sort_values(["RealizedPnL", "WinRate"], ascending=[False, False]).reset_index(drop=True)
    except Exception as _suppressed_exc:
        _log_suppressed_exception("build_roi_dashboard_summary", _suppressed_exc)
        return pd.DataFrame(columns=["Mode", "Coin", "Trades", "Wins", "Losses", "WinRate", "RealizedPnL", "Fees"])


