def build_time_of_day_performance_map():
    try:
        df = load_trade_history()
        if df is None or df.empty or "Tid" not in df.columns:
            return pd.DataFrame(columns=["Weekday", "Hour", "Trades", "WinRate", "RealizedPnL"])
        df = df.copy()
        if "Utfall" in df.columns:
            df = df[~df["Utfall"].astype(str).str.contains("MANUELLT SYSTEMTEST", case=False, na=False)]
        side_series = df["Typ"] if "Typ" in df.columns else pd.Series([""] * len(df), index=df.index)
        df = df[side_series.astype(str).str.upper() == "SELL"].copy()
        if df.empty:
            return pd.DataFrame(columns=["Weekday", "Hour", "Trades", "WinRate", "RealizedPnL"])
        df["ParsedTime"] = pd.to_datetime(df["Tid"], errors="coerce")
        df = df[df["ParsedTime"].notna()].copy()
        if df.empty:
            return pd.DataFrame(columns=["Weekday", "Hour", "Trades", "WinRate", "RealizedPnL"])
        outcome_series = df["Utfall"] if "Utfall" in df.columns else pd.Series([""] * len(df), index=df.index)
        df["PnL_USDT"] = outcome_series.map(_extract_realized_pnl_usdt_from_utfall)
        df["WeekdayNum"] = df["ParsedTime"].dt.weekday
        df["Hour"] = df["ParsedTime"].dt.hour
        rows = []
        for (weekday_num, hour), group in df.groupby(["WeekdayNum", "Hour"], dropna=False):
            trades = int(len(group))
            wins = int((group["PnL_USDT"] > 0).sum())
            rows.append({
                "Weekday": int(weekday_num),
                "Hour": int(hour),
                "Trades": trades,
                "WinRate": round((wins / trades * 100.0) if trades else 0.0, 1),
                "RealizedPnL": round(float(group["PnL_USDT"].sum()), 2),
            })
        out = pd.DataFrame(rows)
        if out.empty:
            return out
        return out.sort_values(["RealizedPnL", "Trades"], ascending=[False, False]).reset_index(drop=True)
    except Exception as _suppressed_exc:
        _log_suppressed_exception("build_time_of_day_performance_map", _suppressed_exc)
        return pd.DataFrame(columns=["Weekday", "Hour", "Trades", "WinRate", "RealizedPnL"])


