def load_trade_reason_rows(max_lines=3000):
    try:
        if not os.path.exists(TRADE_REASON_FILE):
            return []
        with open(TRADE_REASON_FILE, "r", encoding="utf-8-sig") as f:
            lines = f.readlines()[-int(max_lines):]
        rows = []
        for line in lines:
            try:
                item = json.loads(line)
                if isinstance(item, dict):
                    rows.append(item)
            except Exception as parse_err:
                _log_suppressed_exception("load_trade_reason_rows_parse", parse_err, min_interval_seconds=300)
        return rows
    except Exception as _suppressed_exc:
        _log_suppressed_exception("load_trade_reason_rows", _suppressed_exc)
        return []


def build_false_positive_report():
    try:
        df = load_trade_history()
        if df is None or df.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Losses", "TotalLoss", "WorstLoss", "AvgLoss", "CommonReason"])
        df = df.copy()
        if "Utfall" in df.columns:
            df = df[~df["Utfall"].astype(str).str.contains("MANUELLT SYSTEMTEST", case=False, na=False)]
        if df.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Losses", "TotalLoss", "WorstLoss", "AvgLoss", "CommonReason"])

        side_series = df["Typ"] if "Typ" in df.columns else pd.Series([""] * len(df), index=df.index)
        df = df[side_series.astype(str).str.upper() == "SELL"].copy()
        if df.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Losses", "TotalLoss", "WorstLoss", "AvgLoss", "CommonReason"])
        outcome_series = df["Utfall"] if "Utfall" in df.columns else pd.Series([""] * len(df), index=df.index)
        symbol_series = df["Symbol"] if "Symbol" in df.columns else pd.Series([""] * len(df), index=df.index)
        mode_series = df["Trading_Mode"] if "Trading_Mode" in df.columns else pd.Series([""] * len(df), index=df.index)
        df["PnL_USDT"] = outcome_series.map(_extract_realized_pnl_usdt_from_utfall)
        df = df[df["PnL_USDT"] < 0].copy()
        if df.empty:
            return pd.DataFrame(columns=["Mode", "Coin", "Losses", "TotalLoss", "WorstLoss", "AvgLoss", "CommonReason"])
        df["Mode"] = mode_series.map(lambda item: get_trading_mode_badge(normalize_trading_mode(item)))
        df["Coin"] = symbol_series.astype(str).str.upper().str.replace("/USDT", "", regex=False)

        reason_rows = load_trade_reason_rows()
        latest_reason_by_key = {}
        for item in reason_rows:
            try:
                mode = get_trading_mode_badge(normalize_trading_mode(item.get("trading_mode")))
                coin = _normalize_position_coin(item.get("coin") or str(item.get("symbol", "")).split("/")[0])
                reason_payload = item.get("reason", {})
                reason_name = reason_payload.get("reason") if isinstance(reason_payload, dict) else ""
                latest_reason_by_key[(mode, coin)] = str(reason_name or item.get("event_type") or "unknown")
            except Exception as reason_err:
                _log_suppressed_exception("false_positive_reason_map", reason_err, min_interval_seconds=300)

        rows = []
        for (mode, coin), group in df.groupby(["Mode", "Coin"], dropna=False):
            losses = int(len(group))
            total_loss = float(group["PnL_USDT"].sum())
            worst_loss = float(group["PnL_USDT"].min())
            rows.append({
                "Mode": mode or "-",
                "Coin": coin or "-",
                "Losses": losses,
                "TotalLoss": round(total_loss, 2),
                "WorstLoss": round(worst_loss, 2),
                "AvgLoss": round(total_loss / max(losses, 1), 2),
                "CommonReason": latest_reason_by_key.get((mode, coin), "unknown"),
            })
        out = pd.DataFrame(rows).sort_values(["TotalLoss", "Losses"], ascending=[True, False]).reset_index(drop=True)
        try:
            with FALSE_POSITIVE_LOCK:
                atomic_write_json_file(
                    FALSE_POSITIVE_REPORT_FILE,
                    {"updated_at": datetime.now().isoformat(timespec="seconds"), "rows": out.to_dict(orient="records")},
                    indent=2
                )
        except Exception as write_err:
            _log_suppressed_exception("false_positive_report_write", write_err)
        return out
    except Exception as _suppressed_exc:
        _log_suppressed_exception("build_false_positive_report", _suppressed_exc)
        return pd.DataFrame(columns=["Mode", "Coin", "Losses", "TotalLoss", "WorstLoss", "AvgLoss", "CommonReason"])


