            with rg_cols[2]:
                st.number_input("ATR halt threshold %" if english_ui else "ATR-stoppgräns %", min_value=0.0, max_value=100.0, step=0.5, value=float(risk_governor_settings.get("risk_emergency_volatility_halt_pct", 8.0)), key="risk_emergency_volatility_halt_pct_input")
