        for restored_position in load_open_positions().values():
            if not isinstance(restored_position, dict):
                continue
            restored_coin = _normalize_position_coin(restored_position.get("coin"))
            if restored_coin not in restored_position_coins:
                continue
            restored_mode = normalize_trading_mode(restored_position.get("trading_mode", "swing")).upper()
            restored_label = f"{restored_mode}:{restored_coin}"
